// 缓存配置：
// - 本地缓存：30分钟（用于快速响应，避免频繁查询云数据库）
// - 云数据库缓存：3.5小时（由云函数同步，主要数据源）
// 云函数每3小时执行1次，云数据库缓存有效期3.5小时，确保在同步间隔期间数据仍然可用
const { CACHE_PREFIX, CACHE_DURATION } = require('./cache-constants.js')
const STALE_CACHE_MAX_AGE = 4 * 60 * 60 * 1000 // 4 小时 - 过期缓存最大可用时间（stale-while-revalidate）
const CLOUD_CACHE_DURATION = 3.5 * 60 * 60 * 1000 // 3.5小时（毫秒）- 云数据库缓存有效期

// ── 内存缓存层：避免同一 key 反复调用 getStorageSync ──
const _memCache = Object.create(null)   // { key: { data, expireAt } }
// ── storage 同步读取去重层：记录每个 key 上一次同步读到的"原始 entry"，
// 让 stale 探测也能复用，从根源消除"重复读同一 key"的告警 ──
const _storageReadCache = Object.create(null) // { key: { entry, expireAt } }
const STORAGE_READ_DEDUP_TTL = 60 * 1000

function _memGet(key) {
  const entry = _memCache[key]
  if (!entry) return undefined          // undefined = 未命中
  if (Date.now() > entry.expireAt) {
    delete _memCache[key]
    return undefined
  }
  return entry.data                     // 可能是 null（表示"已读过，确认无缓存"）
}

function _memSet(key, data, ttl) {
  _memCache[key] = { data, expireAt: Date.now() + ttl }
}

function _memDel(key) {
  delete _memCache[key]
}

/**
 * 同步读取 storage，但带去重层。同一个 key 在 STORAGE_READ_DEDUP_TTL 内
 * 只真正同步读 1 次，后续直接复用结果。
 * 这样 stale / non-stale 两条路径就不会重复读同一 key。
 * @returns {*|null} storage 中保存的原始对象（含 timestamp），不存在返回 null
 */
function _readStorageEntryDeduped(cacheKey) {
  const cached = _storageReadCache[cacheKey]
  if (cached && Date.now() < cached.expireAt) {
    return cached.entry
  }
  let entry = null
  try {
    entry = wx.getStorageSync(cacheKey) || null
  } catch (e) {
    entry = null
  }
  _storageReadCache[cacheKey] = {
    entry,
    expireAt: Date.now() + STORAGE_READ_DEDUP_TTL
  }
  return entry
}

function _invalidateStorageReadCache(cacheKey) {
  delete _storageReadCache[cacheKey]
}
// 重试配置
const MAX_RETRIES = USE_DEV_API ? 3 : 2 // 开发环境重试3次，生产环境2次
const RETRY_DELAY = 1000 // 重试延迟1秒

// 生产环境请求频率限制：每小时最多15次
const MAX_REQUESTS_PER_HOUR = 15
const REQUEST_COUNT_KEY = 'api_request_count'
const REQUEST_COUNT_RESET_KEY = 'api_request_count_reset'

// 云缓存查询去重与节流：避免同一时刻大量重复查询触发数据库超时
const pendingCloudCacheRequests = Object.create(null)
const cloudCacheBgCheckAt = Object.create(null)
const CLOUD_CACHE_BG_CHECK_INTERVAL = 2 * 60 * 1000 // 2分钟

// ── 后台缓存更新监听器 ──
// 当 request 命中本地缓存后，后台发现云数据库有更新时，通知订阅方刷新 UI
const _staleUpdateListeners = Object.create(null)

/**
 * 注册后台缓存更新监听器
 * @param {String} cacheKey 缓存 key
 * @param {Function} callback 回调函数，参数为新数据
 * @returns {Function} 取消监听的函数
 */
function onStaleUpdate(cacheKey, callback) {
  if (!_staleUpdateListeners[cacheKey]) {
    _staleUpdateListeners[cacheKey] = []
  }
  _staleUpdateListeners[cacheKey].push(callback)
  return function off() {
    const arr = _staleUpdateListeners[cacheKey]
    if (!arr) return
    const idx = arr.indexOf(callback)
    if (idx !== -1) arr.splice(idx, 1)
    if (arr.length === 0) delete _staleUpdateListeners[cacheKey]
  }
}

function _fireStaleUpdate(cacheKey, newData) {
  const arr = _staleUpdateListeners[cacheKey]
  if (!arr || arr.length === 0) return
  arr.slice().forEach(fn => {
    try { fn(newData) } catch (e) { console.error('[staleUpdate] callback error:', e) }
  })
}

/**
 * 检查是否超过请求频率限制
 * @returns {Boolean} true表示超过限制，false表示未超过
 */
function checkRateLimit() {
  if (USE_DEV_API) {
    // 开发环境不限制
    return false
  }
  
  try {
    const now = Date.now()
    const resetTime = wx.getStorageSync(REQUEST_COUNT_RESET_KEY) || now
    const requestCount = wx.getStorageSync(REQUEST_COUNT_KEY) || 0
    
    // 如果超过1小时，重置计数
    if (now - resetTime >= 60 * 60 * 1000) {
      wx.setStorageSync(REQUEST_COUNT_KEY, 0)
      wx.setStorageSync(REQUEST_COUNT_RESET_KEY, now)
      return false
    }
    
    // 检查是否超过限制
    if (requestCount >= MAX_REQUESTS_PER_HOUR) {
      return true
    }
    
    return false
  } catch (error) {
    // 如果存储失败，允许请求（避免因存储问题导致功能不可用）
    return false
  }
}

/**
 * 生成缓存key
 * @param {String} url API路径
 * @param {Object} params 请求参数
 * @returns {String} 缓存key
 */
function getCacheKey(url, params = {}) {
  // 对参数对象进行排序，确保属性顺序一致，避免 cacheKey 不匹配
  const sortedParams = Object.keys(params)
    .sort()
    .reduce((sorted, key) => {
      sorted[key] = params[key]
      return sorted
    }, {})
  const paramsStr = JSON.stringify(sortedParams)

  // launches 列表：云端同步使用轻量列表缓存（key 追加 _slim）
  // 这里保持与云函数的规则一致：upcoming/previous 且 mode=detailed
  const shouldUseSlimList = typeof url === 'string' &&
    (url.includes('/launches/upcoming/') || url.includes('/launches/previous/')) &&
    params && typeof params === 'object' && params.mode === 'detailed'

  // _v4 是当前 slim schema 版本号——每次列表瘦身规则变更都必须同步云端与前端，避免读到缺字段的「僵尸数据」
  //   v1: 初始轻量 schema
  //   v2: detail 单条缓存保留 landing.type/success 等
  //   v3: 列表 slim 保留 landing.success + spacecraft_stage + launcher_stage
  //   v4: 保留 mission.orbit 及载荷 orbit（与云 slimLaunch 一致，供详情「任务轨道」）
  const SLIM_LIST_VERSION = '_v4'
  return `${CACHE_PREFIX}${url}_${paramsStr}${shouldUseSlimList ? '_slim' + SLIM_LIST_VERSION : ''}`
}

/**
 * 从本地存储获取缓存数据（同步）
 * 内部走两级缓存：
 *   1. _memCache —— 仅缓存「新鲜数据」(非 stale)
 *   2. _storageReadCache —— 缓存 storage 同步读到的「原始 entry」，
 *      stale / non-stale 路径共享，避免重复 getStorageSync
 * @param {String} cacheKey 缓存key
 * @param {Boolean} allowStale 是否允许返回过期但未超龄的数据（stale-while-revalidate）
 * @returns {Object|null} 缓存数据，如果不存在或已过期则返回null
 */
function getCacheFromLocal(cacheKey, allowStale) {
  try {
    if (!allowStale) {
      const mem = _memGet(cacheKey)
      if (mem !== undefined) return mem
    }

    // 通过去重层读 storage：同一个 key 在 60s 内只真正 sync 读 1 次
    const cacheData = _readStorageEntryDeduped(cacheKey)
    if (!cacheData) {
      if (!allowStale) _memSet(cacheKey, null, 60 * 1000)
      return null
    }

    const now = Date.now()
    const age = now - cacheData.timestamp

    if (age <= CACHE_DURATION) {
      const remainTTL = CACHE_DURATION - age
      _memSet(cacheKey, cacheData.data, remainTTL)
      return cacheData.data
    }

    // 缓存已过期
    if (allowStale && age <= STALE_CACHE_MAX_AGE) {
      return cacheData.data
    }

    // 完全过期，异步删除存储并清掉去重层（不阻塞主线程）
    try {
      wx.removeStorage({ key: cacheKey, fail: () => {} })
    } catch (e) {}
    _memDel(cacheKey)
    _invalidateStorageReadCache(cacheKey)
    return null
  } catch (error) {
    return null
  }
}

/**
 * 从云数据库获取缓存数据（异步）
 * @param {String} cacheKey 缓存key
 * @returns {Promise<Object|null>} 缓存数据，如果不存在或已过期则返回null
 */
async function getCacheFromCloud(cacheKey, timeout = 5000) {
  if (!cacheKey) return null

  // 同一个 cacheKey 在同一时间只发起一次云查询，其他调用复用同一个 Promise
  if (pendingCloudCacheRequests[cacheKey]) {
    return pendingCloudCacheRequests[cacheKey]
  }

  const requestPromise = (async () => {
    try {
      if (!wx.cloud || !wx.cloud.database) {
        return null
      }

      const db = wx.cloud.database()
      const result = await Promise.race([
        db.collection('space_devs_cache').doc(cacheKey).get(),
        new Promise((_, reject) => setTimeout(() => reject(new Error('云数据库查询超时')), timeout))
      ])

      if (!result.data) return null

      let apiData = result.data.data || null
      if (!apiData && result.data.results && Array.isArray(result.data.results)) {
        apiData = result.data
      }
      if (!apiData) return null

      apiData = unwrapCacheData(apiData)

      if (apiData.isBatched && apiData.batchKeys && Array.isArray(apiData.batchKeys)) {
        const batchPromises = apiData.batchKeys.map(async (batchKey) => {
          try {
            const batchResult = await Promise.race([
              db.collection('space_devs_cache').doc(batchKey).get(),
              new Promise((_, reject) => setTimeout(() => reject(new Error('批次查询超时')), 5000))
            ])
            return (batchResult.data && batchResult.data.data && batchResult.data.data.results) || []
          } catch (batchError) {
            return []
          }
        })

        const batchResults = await Promise.all(batchPromises)
        const mergedResults = batchResults.reduce((all, chunk) => all.concat(chunk || []), [])
        apiData = {
          ...apiData,
          results: mergedResults,
          count: mergedResults.length,
          isBatched: false
        }
      }

      if (!apiData.results || !Array.isArray(apiData.results)) {
        // 兼容单对象 API（如 /space_stations/4/），没有 results 数组但有 id 字段
        if (apiData.id) {
          try {
            setCache(cacheKey, apiData)
          } catch (error) {}
          return apiData
        }
        return null
      }

      try {
        setCache(cacheKey, apiData)
      } catch (error) {}

      return apiData
    } catch (error) {
      const isSizeExceedError = error.errCode === -602001 ||
        (error.errMsg && error.errMsg.includes('exceed limit')) ||
        (error.errMsg && error.errMsg.includes('1MB'))

      if (isSizeExceedError) {
        const localCache = getCacheFromLocal(cacheKey)
        if (localCache !== null) return localCache
      }

      return null
    }
  })()

  pendingCloudCacheRequests[cacheKey] = requestPromise

  try {
    return await requestPromise
  } finally {
    delete pendingCloudCacheRequests[cacheKey]
  }
}

/**
 * 获取缓存数据（优先从云数据库读取，降级到本地存储）
 * @param {String} cacheKey 缓存key
 * @returns {Object|null} 缓存数据，如果不存在或已过期则返回null
 * 
 * 注意：此函数保持同步接口以兼容现有代码
 * 实际会先尝试本地缓存（快速），同时异步检查云数据库（后台更新）
 */
function getCache(cacheKey) {
  // 先尝试本地缓存（同步，快速响应）
  const localCache = getCacheFromLocal(cacheKey)
  if (localCache !== null) {
    // 后台异步检查云数据库是否有更新数据（不阻塞当前返回）
    // 增加节流，避免频繁重复查询导致云数据库超时
    const now = Date.now()
    const lastBgCheckAt = cloudCacheBgCheckAt[cacheKey] || 0
    if (now - lastBgCheckAt >= CLOUD_CACHE_BG_CHECK_INTERVAL) {
      cloudCacheBgCheckAt[cacheKey] = now
      getCacheFromCloud(cacheKey, 3000).then(cloudCache => {
        if (cloudCache !== null && cloudCache !== localCache) {
          // 云数据库有更新数据，更新本地缓存
          try {
            setCache(cacheKey, cloudCache)
          } catch (error) {
            // 静默失败
          }
        }
      }).catch(() => {
        // 静默失败
      })
    }
    return localCache
  }

  // 本地缓存不存在，返回null（调用方会继续请求API）
  // 注意：这里不等待云数据库查询，因为需要保持同步接口
  // 如果需要优先使用云数据库，应该在调用 request 函数前先调用 getCacheFromCloudAsync
  return null
}


/**
 * 清理数据中的 undefined、function 等不可序列化的值，确保可以正确序列化为 JSON
 * 使用简单的 JSON 序列化/反序列化即可
 * @param {*} obj 要清理的对象
 * @returns {*} 清理后的对象
 */
function cleanDataForJSON(obj) {
  if (obj === null || obj === undefined) {
    return null
  }
  
  // 使用 JSON 序列化/反序列化来清理数据（自动处理循环引用、undefined、function等）
  try {
    return JSON.parse(JSON.stringify(obj))
  } catch (error) {
    // 如果序列化失败，返回 null
    return null
  }
}

/**
 * 保存缓存到云数据库（异步）
 * @param {String} cacheKey 缓存key
 * @param {*} data 要缓存的数据
 * @returns {Promise} 保存结果
 */
async function setCacheToCloud(cacheKey, data) {
  try {
    // 验证参数
    if (!cacheKey || typeof cacheKey !== 'string') {
      return false
    }
    
    if (data === null || data === undefined) {
      return false
    }
    
    // 检查是否已初始化云开发
    if (!wx.cloud || !wx.cloud.database) {
      return false
    }

    const db = wx.cloud.database()
    const now = Date.now()
    const expireAt = now + CLOUD_CACHE_DURATION

    // 清理数据（简单的 JSON 序列化/反序列化）
    const cleanedData = cleanDataForJSON(data)
    if (!cleanedData) {
      return false
    }
    
    // 构建缓存数据，格式与云函数保持一致
    const cacheData = {
      data: cleanedData,
      timestamp: now,
      expireAt: expireAt,
      updatedAt: now
    }

    // 保存到云数据库
    await db.collection('space_devs_cache').doc(cacheKey).set({
      data: cacheData
    })

    return true
  } catch (error) {
    // 云数据库保存失败，静默失败（不影响本地缓存）
    return false
  }
}

/**
 * 设置缓存数据（同时保存到本地和云数据库）
 * @param {String} cacheKey 缓存key
 * @param {*} data 要缓存的数据
 * 
 * 注意：优先保存到本地（同步），然后异步保存到云数据库（所有用户共享缓存）
 */
function setCache(cacheKey, data) {
  // 本地缓存最大字节数（避免触发 10MB 上限；并给其它业务留空间）
  const MAX_LOCAL_CACHE_BYTES = 512 * 1024 // 512KB

  const estimateBytes = (obj) => {
    try {
      const str = JSON.stringify(obj)
      return str.length * 3
    } catch (e) {
      return Number.POSITIVE_INFINITY
    }
  }

  try {
    // 验证参数
    if (!cacheKey || typeof cacheKey !== 'string') {
      return
    }

    if (data === null || data === undefined) {
      return
    }

    const cacheData = {
      data: data,
      timestamp: Date.now()
    }

    const bytes = estimateBytes(cacheData)

    // 过大的数据不写入本地 storage（否则很容易超过 10MB 总上限）
    if (bytes > MAX_LOCAL_CACHE_BYTES) {
      return
    }

    // 先保存到本地（同步，快速）
    wx.setStorageSync(cacheKey, cacheData)
    // 同步写入内存缓存
    _memSet(cacheKey, data, CACHE_DURATION)
    // 同步刷新去重层，避免后续读取拿到旧的"原始 entry"
    _storageReadCache[cacheKey] = {
      entry: cacheData,
      expireAt: Date.now() + STORAGE_READ_DEDUP_TTL
    }
  } catch (error) {
    // 如果存储空间不足，尝试清理旧缓存
    if (error.errMsg && error.errMsg.includes('exceed')) {
      clearExpiredCache()
      // 重试一次（仍然要做大小保护）
      try {
        if (cacheKey && typeof cacheKey === 'string') {
          const cacheData = {
            data: data,
            timestamp: Date.now()
          }
          const bytes = estimateBytes(cacheData)
          if (bytes <= MAX_LOCAL_CACHE_BYTES) {
            wx.setStorageSync(cacheKey, cacheData)
            _memSet(cacheKey, data, CACHE_DURATION)
            _storageReadCache[cacheKey] = {
              entry: cacheData,
              expireAt: Date.now() + STORAGE_READ_DEDUP_TTL
            }
          }
        }
      } catch (retryError) {
        // 静默失败
      }
    }
  }
}

/**
 * 清理过期的缓存（实现见 api-cache-clean.js，与 app 启动清理共用）
 */
function clearExpiredCache() {
  cleanExpiredApiCache()
}

/**
 * 构建缓存候选 key 列表（按命中概率降序排列，已去重）
 * 供 request() 在精确 key 未命中时依次探查
 */
function _buildCandidateKeys(url, params, exactKey) {
  const candidates = []
  const seen = new Set()
  function add(key, needsSlice) {
    if (seen.has(key)) return
    seen.add(key)
    candidates.push({ key, slice: needsSlice })
  }

  add(exactKey, false)

  const isDetailRequest = (/\/launches\/[^\/]+\/?$/.test(url)) &&
    !url.includes('/launches/upcoming') &&
    !url.includes('/launches/previous')
  if (isDetailRequest) return candidates

  const isLaunchList = typeof url === 'string' &&
    (url.includes('/launches/upcoming/') || url.includes('/launches/previous/'))
  const ordering = url.includes('previous') ? '-net' : 'net'
  const isUpcomingList = url.includes('/launches/upcoming/')

  // 当前 slim schema 版本号对应的列表后缀（与 getCacheKey 保持一致）
  // 旧版后缀做兜底：新缓存没来时，先让用户看到"不一定有颜色但能展示"的老数据，别白屏；
  // 云函数后台刷新后会自动覆盖为新版带颜色的缓存。
  const SLIM_SUFFIX = '_slim_v4'
  const LEGACY_SLIM_SUFFIXES = ['_slim_v3', '_slim_v2', '_slim']

  function addSlimListCandidates(fullKey) {
    add(fullKey, true)
    if (isLaunchList && fullKey.endsWith(SLIM_SUFFIX)) {
      const rootKey = fullKey.slice(0, -SLIM_SUFFIX.length)
      LEGACY_SLIM_SUFFIXES.forEach((sfx) => add(rootKey + sfx, true))
      add(rootKey, true)
    }
  }

  // upcoming 与 LL2 对齐：默认带 hide_recent_previous；仍候选无该参数的旧云缓存键
  const std100Base = { limit: 100, offset: 0, ordering, mode: 'detailed', format: 'json' }
  const std100Params = isUpcomingList ? { ...std100Base, hide_recent_previous: true } : std100Base
  addSlimListCandidates(getCacheKey(url, std100Params))
  if (isUpcomingList) {
    const kNew = getCacheKey(url, std100Params)
    const kLegacy = getCacheKey(url, std100Base)
    if (kLegacy !== kNew) addSlimListCandidates(kLegacy)
  }

  const std20Base = { limit: 20, offset: 0, ordering, mode: 'detailed', format: 'json' }
  const std20Params = isUpcomingList ? { ...std20Base, hide_recent_previous: true } : std20Base
  addSlimListCandidates(getCacheKey(url, std20Params))
  if (isUpcomingList) {
    const kNew = getCacheKey(url, std20Params)
    const kLegacy = getCacheKey(url, std20Base)
    if (kLegacy !== kNew) addSlimListCandidates(kLegacy)
  }

  if (params.offset && params.offset > 0) {
    add(getCacheKey(url, { ...params, offset: 0 }), true)
  }
  if (params.limit && params.limit !== 100) {
    add(getCacheKey(url, { ...params, limit: 100 }), true)
  }
  if (params.limit && params.limit !== 20) {
    add(getCacheKey(url, { ...params, limit: 20 }), true)
  }

  return candidates
}

/**
 * 从完整缓存中按 params 切出所需的分页数据
 */
function _sliceCacheResult(cache, params) {
  if (!cache || !cache.results || !Array.isArray(cache.results)) return null
  const start = params.offset || 0
  const end = start + (params.limit || 10)
  const sliced = cache.results.slice(start, end)
  return {
    ...cache,
    results: sliced,
    count: cache.count || cache.results.length,
    next: sliced.length > 0 && end < cache.results.length ? (cache.next || 'has_more') : null
  }
}

/**
 * 通用请求方法 - 对接Launch Library API（带缓存和重试）
 * @param {String} url API路径
 * @param {Object} params 请求参数
 * @param {Number} timeout 超时时间（毫秒），开发环境默认20000，生产环境默认10000
 * @param {Boolean} useCache 是否使用缓存，默认true
 * @param {Number} retryCount 当前重试次数（内部使用）
 * @returns {Promise} 返回请求结果
 */
function request(url, params = {}, timeout = null, useCache = true, retryCount = 0) {
  if (timeout === null) {
    timeout = USE_DEV_API ? 20000 : 10000
  }
  return new Promise(async (resolve, reject) => {
    const cacheKey = getCacheKey(url, params)

    if (useCache) {
      // Phase 1: 精确 key 本地缓存命中（零成本、零延迟）
      const localExact = getCacheFromLocal(cacheKey)
      if (localExact !== null) {
        resolve(localExact)
        const now = Date.now()
        const lastBg = cloudCacheBgCheckAt[cacheKey] || 0
        if (now - lastBg >= CLOUD_CACHE_BG_CHECK_INTERVAL) {
          cloudCacheBgCheckAt[cacheKey] = now
          getCacheFromCloud(cacheKey).then(cloud => {
            if (cloud !== null && JSON.stringify(cloud) !== JSON.stringify(localExact)) {
              setCache(cacheKey, cloud)
              _fireStaleUpdate(cacheKey, cloud)
            }
          }).catch(() => {})
        }
        return
      }

      // Phase 2: 构建候选 key，先扫描本地缓存（零成本）
      const candidates = _buildCandidateKeys(url, params, cacheKey)
      for (let i = 1; i < candidates.length; i++) {
        const c = candidates[i]
        const local = getCacheFromLocal(c.key)
        if (local !== null) {
          const result = c.slice ? _sliceCacheResult(local, params) : local
          if (result !== null) {
            resolve(result)
            setCache(cacheKey, result)
            return
          }
        }
      }

      // Phase 2.5: Stale-while-revalidate — 本地缓存刚过期时先用旧数据秒出，后台云端刷新
      let staleResolved = false
      const staleLocal = getCacheFromLocal(cacheKey, true)
      if (staleLocal !== null) {
        resolve(staleLocal)
        staleResolved = true
      }

      // Phase 3: 云数据库查询——并行发起所有候选 key，按优先级取首个有效命中
      try {
        const cloudResults = await Promise.allSettled(
          candidates.map(c => getCacheFromCloud(c.key).then(cloud => ({ cloud, c })))
        )
        for (const r of cloudResults) {
          if (r.status !== 'fulfilled' || !r.value.cloud) continue
          const { cloud, c } = r.value
          const isList = cloud.results && Array.isArray(cloud.results)
          const isSingleObject = !isList && cloud.id
          if (isList) {
            const result = c.slice ? _sliceCacheResult(cloud, params) : cloud
            if (result !== null) {
              if (!staleResolved) resolve(result)
              else _fireStaleUpdate(cacheKey, result)
              setCache(cacheKey, result)
              return
            }
          } else if (isSingleObject) {
            if (!staleResolved) resolve(cloud)
            else _fireStaleUpdate(cacheKey, cloud)
            setCache(cacheKey, cloud)
            return
          }
        }
      } catch (error) {}

      if (staleResolved) return
    }

    reject({
      errMsg: '数据暂不可用，请稍后再试。数据由云函数定时同步，请等待云函数更新缓存。',
      statusCode: 404,
      type: 'cache_miss',
      retryable: false,
      cacheKey: cacheKey
    })
  })
}

/**
 * 检查任务是否已过期
 * @param {String} launchTime 发射时间
 * @returns {Boolean} 是否已过期
 */
function isLaunchExpired(launchTime) {
  if (!launchTime) return true
  const now = new Date().getTime()
  const launchTimeMs = new Date(launchTime).getTime()
  return launchTimeMs <= now
}

/**
 * 格式化发射台+地点，卡片用：「发射台名称 @ 地区/国家」
 * @param {Object} pad launch.pad
 * @returns {String}
 */
function formatPadLocation(pad) {
  if (!pad) return '未知地点'
  const a = pad.name || ''
  const loc = pad.location
  if (!loc) return a || '未知地点'
  let countryStr = loc.country_code || ''
  if (!countryStr && loc.country) {
    countryStr = typeof loc.country === 'string' ? loc.country : (loc.country.name || '')
  }
  const b = [loc.name, countryStr].filter(Boolean).join(', ')
  return b ? `${a} @ ${b}`.trim() : (a || '未知地点')
}

/** country_code / country.name → 发射国家中文，如美国、中国 */
const COUNTRY_DISPLAY = {
  USA: '美国', US: '美国',
  CHN: '中国', CN: '中国', PRC: '中国',
  RUS: '俄罗斯', RU: '俄罗斯',
  JPN: '日本', JP: '日本',
  IND: '印度', IN: '印度',
  KOR: '韩国', KR: '韩国', PRK: '朝鲜', KP: '朝鲜',
  FRA: '法国', FR: '法国',
  GBR: '英国', UK: '英国', GB: '英国',
  DEU: '德国', DE: '德国',
  ITA: '意大利', IT: '意大利',
  ESA: '欧空局', EU: '欧洲',
  NZL: '新西兰', NZ: '新西兰',
  AUS: '澳大利亚', AU: '澳大利亚',
  CAN: '加拿大', CA: '加拿大',
  ISR: '以色列', IL: '以色列',
  IRN: '伊朗', BRA: '巴西',
  UAE: '阿联酋', ARE: '阿联酋',
  SAU: '沙特', MEX: '墨西哥',
  KAZ: '哈萨克斯坦'
}

/** 从任务对象提取可用于国家推断的文本（火箭 full_name、任务名等） */
function collectLaunchCountryHintText(launch) {
  if (!launch || typeof launch !== 'object') return ''
  const parts = []
  if (launch.name) parts.push(String(launch.name))
  const mission = launch.mission
  if (mission && mission.name) parts.push(String(mission.name))
  const configuration =
    (launch.rocket && launch.rocket.configuration) ||
    (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.configuration)
  if (configuration && typeof configuration === 'object') {
    if (configuration.full_name) parts.push(String(configuration.full_name))
    if (configuration.name) parts.push(String(configuration.name))
  }
  return parts.filter(Boolean).join(' ').toLowerCase()
}

function getCountryDisplay(pad, launchServiceProvider = null, launch = null) {
  const loc = pad && pad.location ? pad.location : null

  // 1) 优先使用发射场国家
  let code = loc && loc.country_code ? String(loc.country_code).toUpperCase() : ''

  // 兼容：部分接口会给 GB/UK、UAE/ARE 等
  if (!code && loc && loc.country) {
    const c = loc.country
    if (typeof c === 'string') code = c.toUpperCase().slice(0, 3)
    else if (c && c.abbrev) code = String(c.abbrev || '').toUpperCase()
    else if (c && c.name) return c.name
  }

  // 2) 发射场缺失时，回退到发射服务商国家
  if (!code && launchServiceProvider && launchServiceProvider.country_code) {
    code = String(launchServiceProvider.country_code).toUpperCase()
  }

  // 3) 最后兜底：从地点/发射台/服务商/火箭型号/任务名推断（应对部分接口缺少 country_code）
  if (!code) {
    const hintFromLaunch = collectLaunchCountryHintText(launch)
    const text = [
      loc && loc.name,
      pad && pad.name,
      launchServiceProvider && launchServiceProvider.name,
      launchServiceProvider && launchServiceProvider.abbrev,
      hintFromLaunch
    ]
      .filter(Boolean)
      .join(' ')
      .toLowerCase()

    if (/(\busa\b|united states|vandenberg|cape canaveral|kennedy|florida|california|starbase|boca chica|texas)/.test(text)) code = 'USA'
    else if (/(baikonur|kazakhstan)/.test(text)) code = 'KAZ'
    else if (/(plesetsk|vostochny|russia|russian)/.test(text)) code = 'RUS'
    else if (/(wenchang|jiuquan|taiyuan|xichang|china|\bprc\b)/.test(text)) code = 'CHN'
    else if (/(tanegashima|uchinoura|japan)/.test(text)) code = 'JPN'
    else if (/(sriharikota|india)/.test(text)) code = 'IND'
    else if (/(mahias|kourou|french guiana|guyane)/.test(text)) code = 'FRA'
    else if (/(new zealand|mahia)/.test(text)) code = 'NZL'
    else if (/(uae|united arab emirates|mohammed bin rashid)/.test(text)) code = 'ARE'
    else if (/\buk\b|united kingdom/.test(text)) code = 'GBR'
    else if (/(north korea|\bdprk\b|democratic people|pyongyang)/.test(text)) code = 'PRK'
    else if (/(south korea|republic of korea|south korean|\bkorean\b|\brok\b|daejeon|yeongjongdo|sejong)/.test(text)) code = 'KOR'
    else if (/\bkorea\b/.test(text)) code = 'KOR'
  }

  return COUNTRY_DISPLAY[code] || code || ''
}

/**
 * 状态 → 色标分类：success|failure|partial|delayed|cancelled|pending
 */
function getStatusCategory(status) {
  if (!status) return 'pending'
  const id = status.id
  const n = (status.name || '').toLowerCase()
  const a = (status.abbrev || '').toLowerCase()
  if (id === 3) return 'success'
  if (id === 5) return 'failure'
  if (id === 4) return 'partial'
  if (/delayed|hold|slip|推迟|延迟/.test(n) || /hold|slip/.test(a)) return 'delayed'
  if (/cancel|取消/.test(n)) return 'cancelled'
  return 'pending'
}

/**
 * 状态 → 卡片角标文案：已成功/待发射/取消/失败/推迟/部分失败
 */
function getStatusBadgeText(status, category) {
  if (category === 'success') return '已成功'
  if (category === 'failure') return '失败'
  if (category === 'partial') return '部分失败'
  if (category === 'delayed') return '推迟'
  if (category === 'cancelled') return '取消'
  return '待发射'
}


/**
 * 获取即将推出的任务列表（只返回未过期的任务）
 * 统一使用 /launches/upcoming/ 端点，支持筛选和获取助推器信息
 * @param {Number} limit 返回数量，默认10
 * @param {Number} offset 偏移量，默认0
 * @returns {Promise} 返回任务列表
 */
function mapLaunchToListItem(launch, index, offset, type) {
  const rocketName = getRocketDisplayNameFromLaunch(launch)
  const finalImage = getRocketImage(rocketName)
  const boosterInfo = extractBoosterInfoForList(launch, rocketName, finalImage)
  const status = launch.status || {}
  const statusCategory = getStatusCategory(status)
  const { launchAgency, launchAgencyId, launchAgencyAbbrev } = extractLaunchAgency(launch)
  const _isRecoverable = isRecoverable(boosterInfo)
  const idPrefix = type === 'completed' ? 'completed' : 'mission'

  const item = {
    id: launch.id || `${idPrefix}-${offset + index}`,
    name: launch.name || '',
    missionName: (launch.mission && launch.mission.name) || '',
    rocketName,
    launchSite: (launch.pad && launch.pad.name)
      ? (launch.pad.name + ', ' + ((launch.pad.location && launch.pad.location.name) || '')).trim()
      : '未知地点',
    padLocation: formatPadLocation(launch.pad),
    launchTime: launch.net || launch.window_start,
    windowStart: launch.window_start,
    windowEnd: launch.window_end,
    rocketImage: finalImage,
    rocketConfiguration: pickRocketConfigurationSnapshot(launch),
    status: status.name || (type === 'completed' ? '已完成' : '未知状态'),
    statusAbbrev: status.abbrev || '',
    statusCategory,
    statusBadgeText: getStatusBadgeText(status, statusCategory),
    probability: launch.probability,
    countryDisplay: getCountryDisplay(launch.pad, launch.launch_service_provider, launch),
    launchAgency,
    launchAgencyId,
    launchAgencyAbbrev,
    boosterInfo,
    isRecoverableThisMission: _isRecoverable,
    landingIcon: boosterInfo && (boosterInfo.landingType === 'ASDS' ? 'asds' : (boosterInfo.landingType === 'RTLS' || boosterInfo.landingLocation ? 'rtls' : null)) || null,
    recoveryIcons: extractRecoveryIcons(launch, type === 'completed' ? 'completed' : 'upcoming'),
    ...computeRecoveryTag(boosterInfo, _isRecoverable)
  }

  if (type === 'completed') {
    item.success = (launch.status && launch.status.id) === 3
    item.isPartialFailure = (launch.status && launch.status.id) === 4
    item.isFailure = (launch.status && launch.status.id) === 5
    item.missionDescription = (launch.mission && launch.mission.description) || ''
    item.isExpired = false
  }

  return item
}

function getUpcomingMissions(limit = 10, offset = 0) {
  // 使用 /launches/upcoming/ 端点获取即将推出的任务
  // /launches/upcoming/ 本身只返回未来任务，无需客户端再过滤过期
  return request('/launches/upcoming/', {
    limit: limit,
    offset: offset,
    ordering: 'net',
    mode: 'detailed',
    format: 'json',
    hide_recent_previous: true
  }).then(data => {
    if (!data) {
      return { list: [], hasMore: false, nextOffset: 0 }
    }
    if (!data.results || !Array.isArray(data.results)) {
      return { list: [], hasMore: false, nextOffset: 0 }
    }

    // /launches/upcoming/ 端点直接返回即将发射的任务，不需要过滤
    const upcomingLaunches = data.results
    
    // 转换数据格式，提取助推器信息
    const list = upcomingLaunches.map((launch, index) => mapLaunchToListItem(launch, index, offset, 'upcoming'))
    // 与 getCompletedMissions 完全一致的分页逻辑
    const actualReturnedCount = list.length
    const totalAvailable = Array.isArray(data.results) ? data.results.length : (data.count || 0)
    const hasMore = (offset + actualReturnedCount) < totalAvailable || !!(data && data.next)
    return { list, hasMore: hasMore, nextOffset: offset + actualReturnedCount }
  }).catch(error => {
    throw error
  })
}


/**
 * 获取单个助推器实例的详细信息（用于可回收火箭）
 * @param {String|Number} launcherId 助推器实例ID
 * @returns {Promise} 返回助推器实例详细信息（序列号、飞行次数等）
 */
function getLauncherInstanceDetail(launcherId) {
  if (!launcherId) {
    return Promise.reject(new Error('助推器ID不能为空'))
  }
  
  
  // 优化：使用较短的超时时间，避免长时间等待
  return request(`/launchers/${launcherId}/`, {
    mode: 'detailed'
  }, 5000, false).then(data => {
    if (!data) {
      throw new Error('未找到助推器详情')
    }
    
    const launcher = data
    // 检查是launcher实例还是launcher配置
    // 如果是实例，会有serial_number和flights字段
    // 如果是配置，会有configuration字段
    if (launcher.serial_number || launcher.flights !== undefined) {
      // 这是launcher实例
      const serialNumber = launcher.serial_number || null
      const flights = launcher.flights !== undefined && launcher.flights !== null ? launcher.flights : null
      const successfulLandings = launcher.successful_landings !== undefined && launcher.successful_landings !== null ? launcher.successful_landings : null
      const attemptedLandings = launcher.attempted_landings !== undefined && launcher.attempted_landings !== null ? launcher.attempted_landings : null
      
      return {
        serialNumber: serialNumber,
        flights: flights,
        successfulLandings: successfulLandings,
        attemptedLandings: attemptedLandings,
        flightProven: launcher.flight_proven || false
      }
    } else {
      // 这是launcher配置，不是实例，返回null
      return null
    }
  }).catch(error => {
    throw error
  })
}

/**
 * 获取单个发射任务的详细信息
 * 统一从 /launches/upcoming/ 获取
 * @param {String|Number} launchId 发射任务ID
 * @param {String} type 任务类型（已废弃，统一使用upcoming端点）
 * @returns {Promise} 返回任务详细信息
 */
/**
 * 通过云函数 fetchLaunchDetail 拉取单条 launch 的完整详情
 * 云端命中缓存就秒回；否则云函数会去打 LL2 → slim → 入库 → 返回
 * 返回未经 processLaunchDetail 处理的原始 launch 对象，调用方负责后续加工
 */
function _fetchLaunchDetailViaCloud(launchId, forceRefresh = false) {
  return new Promise((resolve, reject) => {
    if (!wx.cloud || typeof wx.cloud.callFunction !== 'function') {
      reject(new Error('云函数能力不可用'))
      return
    }
    wx.cloud.callFunction({
      name: 'll2Query',
      data: { action: 'fetchLaunchDetail', launchId: String(launchId), forceRefresh: !!forceRefresh },
      timeout: 25000,
      success: (res) => {
        const r = res && res.result
        if (r && r.success && r.data) {
          resolve(r.data)
        } else {
          reject(new Error((r && r.error) || '云函数返回为空'))
        }
      },
      fail: (err) => reject(new Error((err && err.errMsg) || '云函数调用失败'))
    })
  })
}

function getLaunchDetail(launchId, type = 'upcoming') {
  if (!launchId) {
    return Promise.reject(new Error('发射任务ID不能为空'))
  }

  // 多芯火箭/星舰常常因为 list 缓存被 slim 而拿不到完整 launcher_stage / spacecraft_stage
  // → 优先走云函数 fetchLaunchDetail 直接拉 LL2 单条详情（云端带 cache，不会重复打 LL2）
  return _fetchLaunchDetailViaCloud(launchId).then(async data => {
    if (!data) throw new Error('云函数未返回详情')
    return await processLaunchDetail(data)
  }).catch(async (cloudErr) => {
    // 云函数失败 → 回退到原有逻辑（云数据库 list 缓存）
    return request(`/launches/${launchId}/`, {
      mode: 'detailed',
      format: 'json'
    }, 10000, true).then(async data => {
      if (!data) throw new Error('未找到任务详情')
      return await processLaunchDetail(data)
    }).catch(async () => {
      // 最后兜底：扫 upcoming/previous 列表缓存
      const listUrl = type === 'completed' || type === 'previous' ? '/launches/previous/' : '/launches/upcoming/'
      return request(listUrl, {
        mode: 'detailed',
        format: 'json',
        limit: 100,
        ...(listUrl.includes('/upcoming/') ? { hide_recent_previous: true } : {})
      }, 10000, true).then(async data => {
        if (data && data.results && Array.isArray(data.results)) {
          const foundLaunch = data.results.find(launch => {
            const id = launch.id || (launch.url && launch.url.split('/').filter(Boolean).pop())
            return id === launchId || id === String(launchId) || String(id) === String(launchId)
          })
          if (foundLaunch) return await processLaunchDetail(foundLaunch)
        }
        throw new Error('未找到任务详情')
      })
    })
  })
}

/**
 * 从 mission.description 文本中尝试提取载荷数量
 * 支持：载荷数量：5、共 20 颗卫星、携带 3 个载荷、22 satellites、payload_count 等
 * @param {String} str mission.description
 * @returns {Number} 提取到的数量，失败返回 0
 */
function tryExtractPayloadCountFromDescription(str) {
  if (typeof str !== 'string' || !str.trim()) return 0
  const s = str.trim()
  // 1) 显式「载荷数量：N」「载荷：N」
  let m = s.match(/(?:载荷\s*[数量]*\s*[：:]\s*|payload\s*count\s*[：:]\s*)(\d+)/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  // 2) 共/携带/搭载/发射/一箭 + 数字 + 颗/个/枚 + 卫星/载荷/航天器
  m = s.match(/(?:共|携带|搭载|发射|一箭)(?:约)?\s*(\d+)\s*[颗个枚只]?\s*(?:颗|个|枚|只)?\s*(?:卫星|载荷|航天器|飞行器)/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  // 3) 数字 + 颗/个 + 卫星/载荷
  m = s.match(/(\d+)\s*[颗个枚只]?\s*(?:卫星|载荷|航天器|飞行器)/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  // 4) 卫星/载荷 + 数字
  m = s.match(/(?:卫星|载荷)\s*(\d+)\s*[颗个]?/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  // 5) 英文：N satellites、carrying N payload、N payloads
  m = s.match(/(\d+)\s+satellites?/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  m = s.match(/(?:carrying|with|deploying)\s+(\d+)\s+payloads?/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  m = s.match(/(\d+)\s+payloads?/i)
  if (m) return Math.max(0, parseInt(m[1], 10))
  // 6) 若 description 为 JSON 字符串，尝试 payload_count / payloadCount / num_payloads
  try {
    const j = JSON.parse(s)
    if (j != null && typeof j === 'object') {
      const n = (j.payload_count != null ? j.payload_count : (j.payloadCount != null ? j.payloadCount : j.num_payloads))
      if (n != null && !isNaN(Number(n))) return Math.max(0, parseInt(String(n), 10))
    }
  } catch (_) { /* 非 JSON，忽略 */ }
  return 0
}

/** 轨道 abbrev 字段在 LL2 里可能是字符串或小型嵌套对象 */
function normalizeOrbitAbbrevField(raw) {
  if (raw == null || raw === '') return ''
  if (typeof raw === 'string') return raw.trim()
  if (typeof raw === 'object') {
    const a = raw.abbrev != null ? String(raw.abbrev).trim() : ''
    const n = raw.name != null ? String(raw.name).trim() : ''
    return (a || n).trim()
  }
  return String(raw).trim()
}

function buildMissionOrbitDisplayString(orbit) {
  if (!orbit || typeof orbit !== 'object') return ''
  const abbrevStr = normalizeOrbitAbbrevField(orbit.abbrev)
  const name = ((orbit.name != null ? String(orbit.name) : '').trim() ||
    (orbit.full_name != null ? String(orbit.full_name).trim() : ''))
  let orbitStr = [name, abbrevStr ? `(${abbrevStr})` : ''].filter(Boolean).join(' ').trim()
  if (orbit.perigee != null || orbit.apogee != null) {
    orbitStr += (orbitStr ? ' ' : '') + String(orbit.perigee != null ? orbit.perigee : orbit.apogee) + 'km'
    orbitStr = orbitStr.trim()
  }
  return orbitStr
}

function collectLaunchOrbitObjects(launch) {
  const list = []
  const push = (o) => {
    if (!o || typeof o !== 'object') return
    if (!list.includes(o)) list.push(o)
  }
  const mission = launch.mission
  if (mission && mission.orbit) push(mission.orbit)
  const payloads = mission && mission.payloads
  if (Array.isArray(payloads)) {
    for (const p of payloads) {
      if (p && typeof p === 'object' && p.orbit) push(p.orbit)
    }
  }
  const pf = launch.payload_flights
  if (Array.isArray(pf)) {
    for (const row of pf) {
      const payload = row && row.payload
      if (payload && typeof payload === 'object' && payload.orbit) push(payload.orbit)
    }
  }
  return list
}

/** 多条路径解析轨道文案（mission.orbit 常为空但 payload 上会带 orbit） */
function resolveLaunchOrbitStrings(launch) {
  const orbits = collectLaunchOrbitObjects(launch)
  let display = ''
  let shortLabel = ''
  for (const orb of orbits) {
    display = buildMissionOrbitDisplayString(orb)
    shortLabel =
      ((orb.name || orb.full_name || '').toString().trim()) ||
      normalizeOrbitAbbrevField(orb.abbrev)
    if (display || shortLabel) break
  }
  if (!shortLabel && display) shortLabel = display
  return { display: display || '', shortLabel: shortLabel || '' }
}

/**
 * 处理launch详情数据，提取所需信息
 * @param {Object} launch launch数据对象
 * @returns {Promise} 返回处理后的任务详情
 */
async function processLaunchDetail(launch) {
    
    if (!launch) {
      throw new Error('未找到任务详情')
    }
    
    // 提取任务详情信息
    
    // 获取发射机构名称（优先使用launch_service_provider，其次使用program中的agencies）
    const { launchAgency, launchAgencyId, launchAgencyAbbrev } = extractLaunchAgency(launch)
    
    // 获取火箭配置详细信息
    let rocketInfo = ''
    const rocketConfig = (launch.rocket && launch.rocket.configuration)
      || (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.configuration)
    if (rocketConfig) {
      const rocketName = getRocketDisplayNameFromConfig(rocketConfig)
      const rocketDescription = rocketConfig.description || ''
      if (rocketDescription && rocketDescription.trim()) {
        rocketInfo = `${rocketName}：${rocketDescription}`
      } else {
        const manufacturer = (rocketConfig.manufacturer && rocketConfig.manufacturer.name) || ''
        const family = rocketConfig.family || ''
        const variant = rocketConfig.variant || ''
        if (manufacturer || family || variant) {
          const parts = []
          if (manufacturer) parts.push(`制造商：${manufacturer}`)
          if (family) parts.push(`系列：${family}`)
          if (variant) parts.push(`型号：${variant}`)
          rocketInfo = `${rocketName}（${parts.join('，')}）`
        } else {
          rocketInfo = rocketName || ''
        }
      }
    }
    
    // 获取任务详情
    let missionDetails = ''
    const mission = launch.mission
    if (mission) {
      if (mission.description) {
        missionDetails = mission.description
      } else if (mission.type) {
        const missionType = typeof mission.type === 'string' ? mission.type : mission.type.name
        missionDetails = `任务类型：${missionType}。${mission.name || '本次任务'}将执行重要的航天任务。`
      } else if (mission.name) {
        missionDetails = `${mission.name}：本次发射将携带重要载荷进入预定轨道，执行科学实验和观测任务。`
      }
    }
    
    // 获取启动说明（使用mission.description或者mission.name）
    let description = ''
    if (mission && mission.description && mission.description.trim()) {
      description = mission.description
    } else if (mission && mission.name && mission.name.trim()) {
      description = mission.name
    } else if (launch.name && launch.name.trim()) {
      description = launch.name
    }
    
    // 获取发射场信息
    let launchSite = ''
    if (launch.pad && launch.pad.location) {
      const location = launch.pad.location
      const padName = launch.pad.name || ''
      const locationName = location.name || ''
      if (padName && locationName) {
        launchSite = `${padName}, ${locationName}`
      } else if (locationName) {
        launchSite = locationName
      } else if (padName) {
        launchSite = padName
      }
    } else if (launch.pad && launch.pad.name) {
      launchSite = launch.pad.name
    }
    
    // 获取助推器信息（可回收火箭）
    // Launch Library API中，助推器信息可能在多个位置：
    // 1. launch.rocket.launcher_stage (第一级助推器)
    // 2. launch.rocket.rocket.launcher_stage
    // 3. launch.rocket 可能直接包含 launcher 信息
    // 4. 如果launch详情中没有，需要通过/launchers/{id}/端点查询
    let boosterInfo = null
    
    // 尝试多种路径获取助推器信息
    let launcher = null
    let launcherId = null
    
    // 路径1: launch.rocket.launcher_stage (检查小写)
    // 路径1b: launch.rocket.Launcher_stage (检查首字母大写，API可能使用这种格式)
    let launcherStagesArray = null  // 保存原始数组以支持多芯火箭（Falcon Heavy / SLS / 长征五号 等）
    if ((launch.rocket && launch.rocket.launcher_stage) || (launch.rocket && launch.rocket.Launcher_stage)) {
      launcher = launch.rocket.launcher_stage || launch.rocket.Launcher_stage
      
      // 如果launcher是数组，先保存整个数组，再取第一个元素继续走原解析流程
      if (Array.isArray(launcher) && launcher.length > 0) {
        launcherStagesArray = launcher
        launcher = launcher[0]
      }
      
      // launcher可能是对象引用（URL字符串）或完整对象
      if (typeof launcher === 'string') {
        // 如果是URL字符串，提取ID
        launcherId = launcher.split('/').filter(Boolean).pop()
      } else if (launcher && typeof launcher === 'object') {
        // 如果是对象，尝试获取id或从url中提取
        // 先检查所有可能的ID字段
        // 注意：launcher对象可能有嵌套的launcher字段
        // 直接检查launcher.id，如果存在就使用（即使为0也应该使用）
        let possibleId = null
        let possibleUrl = null
        
        if (launcher.id !== undefined && launcher.id !== null) {
          launcherId = launcher.id
          possibleId = launcher.id
        } else {
          // 尝试其他可能的ID字段
          possibleId = launcher.launcher_id || launcher.launcher_instance_id || (launcher.launcher && launcher.launcher.id)
          possibleUrl = launcher.url || launcher.launcher_url || launcher.instance_url || (launcher.launcher && launcher.launcher.url)
          launcherId = possibleId || (possibleUrl ? possibleUrl.split('/').filter(Boolean).pop() : null) || launcherId
        }
      }
    }
    // 路径2: launch.rocket.rocket.launcher_stage (检查小写)
    // 路径2b: launch.rocket.rocket.Launcher_stage (检查首字母大写)
    else if ((launch.rocket && launch.rocket.rocket && launch.rocket.rocket.launcher_stage) || (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.Launcher_stage)) {
      launcher = launch.rocket.rocket.launcher_stage || launch.rocket.rocket.Launcher_stage
      
      if (Array.isArray(launcher) && launcher.length > 0) {
        launcherStagesArray = launcher
        launcher = launcher[0]
      }
      
      launcherId = launcher.id || launcherId
    }
    // 路径3: launch.rocket 本身可能就是 launcher
    else if ((launch.rocket && launch.rocket.serial_number) || (launch.rocket && launch.rocket.flights !== undefined)) {
      launcher = launch.rocket
      launcherId = launcher.id || launcherId
    }
    // 路径4: 检查是否有launcher的ID引用（可能是字符串ID）
    else if ((launch.rocket && launch.rocket.launcher_stage_id) || (launch.rocket && launch.rocket.Launcher_stage_id)) {
      launcherId = launch.rocket.launcher_stage_id || launch.rocket.Launcher_stage_id
    }
    else if ((launch.rocket && launch.rocket.rocket && launch.rocket.rocket.launcher_stage_id) || (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.Launcher_stage_id)) {
      launcherId = launch.rocket.rocket.launcher_stage_id || launch.rocket.rocket.Launcher_stage_id
    }
    
    // 如果找到launcher信息，提取数据
    if (launcher) {
      // 从Launcher_stage数组中提取详细信息
      // 序列号可能在多个位置，优先从launcher.launcher中获取
      let serialNumber = (launcher.launcher && launcher.launcher.serial_number) ||
                        launcher.serial_number ||
                        null
      
      // 如果还没有序列号，尝试从着陆描述中提取（例如："B1080"）
      if (!serialNumber && launcher.landing && launcher.landing.description) {
        const descMatch = launcher.landing.description.match(/B\d+/i) // 匹配 B1080, B1060 等格式
        if (descMatch) {
          serialNumber = descMatch[0]
        }
      }
      
      const textPool = [
        (launcher.landing && launcher.landing.description) || '',
        (mission && mission.description) || '',
        (mission && mission.name) || '',
        launch.name || ''
      ].join(' ')

      // 不再回退到内部 ID（如 886）作为序列号，只从真实序列字段或描述文本中提取 Bxxxx
      if (!serialNumber && textPool) {
        const textSerialMatch = textPool.match(/\bB\d{3,5}\b/i)
        if (textSerialMatch) serialNumber = textSerialMatch[0].toUpperCase()
      }
      
      // 飞行次数可能在 launcher.launcher_flight_number / launcher.flights，或描述中的 "11th flight"
      let flights = launcher.launcher_flight_number !== undefined && launcher.launcher_flight_number !== null 
                    ? launcher.launcher_flight_number 
                    : (launcher.flights !== undefined && launcher.flights !== null ? launcher.flights : null)
      if (flights === null && textPool) {
        const flightMatch = textPool.match(/\b(\d{1,3})(?:st|nd|rd|th)?\s+flight\b/i)
        if (flightMatch) {
          const parsedFlights = Number(flightMatch[1])
          if (!isNaN(parsedFlights)) flights = parsedFlights
        }
      }
      
      // 着陆信息
      const landing = launcher.landing || null
      const landingLocation = (landing && landing.landing_location) || null
      // 优先使用缩写（如ASOG），如果没有缩写则使用全名
      const landingLocationAbbrev = (landingLocation && landingLocation.abbrev) || null
      const landingLocationName = (landingLocation && landingLocation.name) || null
      let landingType = (landingLocation && landingLocation.type) || null
      const landingDescription = (landing && landing.description) || null
      
      // 如果API没有返回着陆地点，尝试从描述提取常见关键词（如 OCISLY / ASOG / JRTI）
      let resolvedLandingLocation = landingLocationAbbrev || landingLocationName || null
      if (!resolvedLandingLocation && landingDescription) {
        const descUpper = String(landingDescription).toUpperCase()
        if (descUpper.includes('OCISLY') || descUpper.includes('OF COURSE I STILL LOVE YOU')) resolvedLandingLocation = 'OCISLY'
        else if (descUpper.includes('ASOG') || descUpper.includes('A SHORTFALL OF GRAVITAS')) resolvedLandingLocation = 'ASOG'
        else if (descUpper.includes('JRTI') || descUpper.includes('JUST READ THE INSTRUCTIONS')) resolvedLandingLocation = 'JRTI'
        else {
          const lzMatch = landingDescription.match(/\bLZ-?\d+\b/i)
          if (lzMatch) resolvedLandingLocation = lzMatch[0].toUpperCase().replace('LZ', 'LZ-')
        }
      }

      // 如果API没有返回landingType，根据着陆地点名称或描述推断
      if (!landingType) {
        const locationText = (resolvedLandingLocation || '').toUpperCase()
        const descText = (landingDescription || '').toUpperCase()
        // 无人船地点（ASDS）
        if (locationText.includes('ASOG') || 
            locationText.includes('OCISLY') || 
            locationText.includes('JRTI') ||
            locationText.includes('A SHORTFALL OF GRAVITAS') ||
            locationText.includes('OF COURSE I STILL LOVE YOU') ||
            locationText.includes('JUST READ THE INSTRUCTIONS') ||
            descText.includes('ASDS') ||
            descText.includes('OCISLY') ||
            descText.includes('ASOG') ||
            descText.includes('JRTI')) {
          landingType = 'ASDS'
        }
        // 陆地回收地点（RTLS）
        else if (locationText.includes('LZ-') || 
                 locationText.includes('LANDING ZONE') ||
                 locationText.includes('LZ1') ||
                 locationText.includes('LZ2') ||
                 locationText.includes('LZ4') ||
                 descText.includes('RTLS') ||
                 /\bLZ-?\d+\b/.test(descText)) {
          landingType = 'RTLS'
        }
      }
      // 统一为 ASDS/RTLS，便于列表与详情弹窗共用
      if (landingType && String(landingType).toUpperCase() === 'ASDS') landingType = 'ASDS'
      else if (landingType && String(landingType).toUpperCase() === 'RTLS') landingType = 'RTLS'
      
      // 成功着陆和尝试着陆次数
      const successfulLandings = (launcher.launcher && launcher.launcher.successful_landings !== undefined)
                                ? launcher.launcher.successful_landings
                                : (launcher.successful_landings !== undefined && launcher.successful_landings !== null ? launcher.successful_landings : null)
      const attemptedLandings = (launcher.launcher && launcher.launcher.attempted_landings !== undefined)
                               ? launcher.launcher.attempted_landings
                               : (launcher.attempted_landings !== undefined && launcher.attempted_landings !== null ? launcher.attempted_landings : null)
      
      // 如果launcher存在，尝试创建boosterInfo
      // 对于可回收火箭（Falcon 9等），即使没有序列号，只要有飞行次数或着陆信息就显示
      if (launcher) {
        // 检查是否有足够的信息创建boosterInfo
        const hasBoosterData = serialNumber || 
                              flights !== null || 
                              resolvedLandingLocation || 
                              landingDescription ||
                              launcher.reused === true
        
        if (hasBoosterData) {
          boosterInfo = {
            serialNumber: serialNumber || null,
            flights: flights,
            successfulLandings: successfulLandings,
            attemptedLandings: attemptedLandings,
            flightProven: launcher.flight_proven || (launcher.launcher && launcher.launcher.flight_proven) || false,
            // 优先显示缩写（如ASOG），如果没有缩写则显示全名；若 API 未给则从描述提取
            landingLocation: resolvedLandingLocation,
            landingLocationAbbrev: landingLocationAbbrev || (resolvedLandingLocation && /^[A-Z0-9-]{2,10}$/.test(resolvedLandingLocation) ? resolvedLandingLocation : null),
            landingType: landingType,
            landingDescription: landingDescription,
            reused: launcher.reused || false
          }
        } else {
          // 如果launcher有url，尝试从URL中提取ID
          if (!launcherId && launcher.url) {
            launcherId = launcher.url.split('/').filter(Boolean).pop()
          }
        }
      }
    }
    
    // 如果launch详情中没有完整的launcher信息，但有launcher ID，尝试查询launchers端点
    // 优化：只在确实需要时才调用，避免不必要的API请求
    // 检查launch详情中是否已经有足够的launcher信息，如果没有才调用API
    const needsLauncherDetail = !boosterInfo && 
                                 launcherId && 
                                 typeof launcherId === 'string' && 
                                 launcherId.trim() !== '' &&
                                 (!launcher || !launcher.serial_number) // 如果launch详情中已经有序列号，就不需要额外请求
    
    if (needsLauncherDetail) {
      try {
        // 使用较短的超时时间，避免长时间等待
        const launcherDetail = await getLauncherInstanceDetail(launcherId)
        if (launcherDetail && (launcherDetail.serialNumber || launcherDetail.flights !== null)) {
          boosterInfo = launcherDetail
        }
      } catch (error) {
        // 静默失败，不影响主流程
        // 如果查询失败，尝试使用launch详情中的基本信息
        if (launcher) {
          boosterInfo = {
            serialNumber: launcher.serial_number || null,
            flights: launcher.flights || null,
            successfulLandings: launcher.successful_landings || null,
            attemptedLandings: launcher.attempted_landings || null,
            flightProven: launcher.flight_proven || false
          }
        }
      }
    }
    
    // 优化：移除 /launchers/ 列表查询，因为：
    // 1. launch详情应该已经包含launcher信息
    // 2. 如果没有launcherId，列表查询无法精确匹配
    // 3. 这个查询容易超时且通常不必要
    // 如果launch详情中没有launcher信息，说明API不支持，不需要额外查询
    
    // 可回收火箭推断兜底（复用共享逻辑）
    const rocketName = getRocketDisplayNameFromLaunch(launch)
    const finalImage = getRocketImage(rocketName)
    boosterInfo = inferRecoveryFallback(launch, rocketName, finalImage, boosterInfo)

    // 多芯火箭支持（Falcon Heavy 中央芯+2 助推 / SLS / 长征五号 等）
    // LL2 API 对这类任务会在 launcher_stage 里返回多个元素，每个对应一根芯。
    // 上面的解析只取了第一个（boosterInfo），这里把整组解析出来给前端做 wx:for。
    //
    // 同时：星舰（Starship/Super Heavy）任务会在 spacecraft_stage 里额外返回飞船信息，
    // 这里也一起聚合，让"助推器/回收"区块同时显示 Super Heavy + Starship。
    let boosterStages = null
    const stageRoleMap = {
      core: '中央芯',
      side: '侧助推器',
      booster: '助推器',
      first_stage: '一级',
      strap_on: '助推器'
    }
    // 着陆类型 → 中文映射（除已有 ASDS / RTLS 外，新增星舰常见的几种）
    function normalizeLandingType(raw) {
      if (!raw) return null
      const v = String(raw).toUpperCase().replace(/[\s_-]+/g, '')
      // LL2 abbrev 简写
      if (v === 'EXP' || v === 'EXPENDED' || v === 'EXPENDABLE' || v === 'DISPOSED') return 'EXPENDED'
      if (v === 'ASDS' || v === 'ASOG' || v === 'OCISLY' || v === 'JRTI') return 'ASDS'
      if (v === 'RTLS') return 'RTLS'
      if (v === 'SD' || v.includes('SPLASHDOWN') || v === 'OCEAN' || v.includes('OCEANLAND')) return 'SPLASHDOWN'
      if (v === 'PR' || v.includes('PARACHUTE') || v.includes('RECOVERY')) return 'RECOVERY'
      if (v === 'TC' || v.includes('TOWER') || v.includes('CATCH') || v.includes('CHOPSTICK') || v.includes('MECHAZILLA')) return 'TOWER_CATCH'
      if (v.includes('LOST') || v.includes('FAILED')) return 'LOST'
      // LL2 全名兜底
      if (v.includes('RETURNTOLAUNCHSITE')) return 'RTLS'
      if (v.includes('AUTONOMOUSSPACEPORT') || v.includes('DRONESHIP') || v.includes('DRONE SHIP')) return 'ASDS'
      return v // 其它保留原值，前端可直接显示
    }

    /**
     * 当 LL2 没给 landing_location.type 时，根据落点缩写/名称智能反推：
     *   - LZ-1/LZ-2/LZ-4/LZ-40 等 SpaceX 陆地着陆区 → RTLS（陆地）
     *   - OCISLY / JRTI / ASOG / ASDS（"Of Course I Still Love You" 等驳船） → ASDS（海上回收）
     *   - ATL / PAC / Indian Ocean / Pacific / Atlantic / Ocean 等海域 → SPLASHDOWN（海面溅落，含一次性使用）
     *   - Mechazilla / Tower / Chopsticks → TOWER_CATCH（星舰塔架捕获）
     */
    function inferLandingTypeFromLocation(abbrev, name) {
      const a = String(abbrev || '').toUpperCase().trim()
      const n = String(name || '').toUpperCase()
      const text = `${a} ${n}`
      if (/\bLZ[\s-]?\d+\b/.test(text)) return 'RTLS'
      if (/\bLC[\s-]?\d+/.test(text) && /(MECHAZILLA|TOWER|CHOPSTICK|CATCH)/.test(text)) return 'TOWER_CATCH'
      if (/\bLZ\b|LANDING\s*ZONE/.test(text)) return 'RTLS'
      if (/OCISLY|JRTI|ASOG|\bASDS\b|OF\s*COURSE\s*I\s*STILL\s*LOVE\s*YOU|JUST\s*READ\s*THE\s*INSTRUCTIONS|SHORTFALL\s*OF\s*GRAVITAS/.test(text)) return 'ASDS'
      if (/MECHAZILLA|TOWER\s*CATCH|CHOPSTICK/.test(text)) return 'TOWER_CATCH'
      if (/\bATL\b|\bPAC\b|ATLANTIC|PACIFIC|INDIAN\s*OCEAN|\bOCEAN\b|SPLASHDOWN/.test(text)) return 'SPLASHDOWN'
      return null
    }

    /**
     * 把 landingType 转成"前端直接渲染"的标签 + 图标路径，避免 WXML 写大段三元
     */
    function buildLandingDisplay(landingType, location, reused, landingStatus) {
      const type = landingType || null
      const loc = location ? String(location).trim() : ''
      const status = landingStatus || 'neutral' // 'success' | 'failure' | 'neutral'

      let typeLabel = ''
      switch (type) {
        case 'RTLS':       typeLabel = '陆地回收';   break
        case 'ASDS':       typeLabel = '海上回收';   break
        case 'SPLASHDOWN': typeLabel = '海面溅落';   break
        case 'RECOVERY':   typeLabel = '海面回收';   break
        case 'EXPENDED':   typeLabel = '一次性使用'; break
        case 'TOWER_CATCH':typeLabel = '塔架捕获';   break
        case 'LOST':       typeLabel = '未能回收';   break
        case 'DRAGON':     typeLabel = '海面溅落';   break  // 龙飞船伞降溅落
        default:           typeLabel = ''           // 未识别：留空，让前端只显示落点名
      }

      // 图标改用 dataURI 内联 SVG —— 颜色随 status 自动变（绿/橙/白）
      // 没匹配到模板（如 TOWER_CATCH / LOST）则 icon 为 null，前端只显示文字
      const icon = buildLandingIcon(type, status)

      // 优先级：实际回收类型（销毁/陆地/海上/塔架捕获…）> "未复用/首次"
      // 因为 EXPENDED/LOST 已经精确说明了本次任务的处置方式，比"未复用/首次"更有信息量
      const isFirstFlight = (reused === false)
      let primary
      if (typeLabel) {
        primary = typeLabel
      } else if (isFirstFlight) {
        primary = '未复用/首次'
      } else {
        primary = ''
      }
      return {
        landingType: type,
        landingStatus: status,
        landingIcon: icon,
        landingLocation: loc || null,
        landingTypeLabel: primary || null,
        landingDisplayText: [primary, loc].filter(Boolean).join(' ') || '—'
      }
    }

    // 兜底：如果前面 boosterInfo 的解析路径没拿到 launcher_stage 数组，
    // 这里独立从所有可能路径再取一次（与 stageInfo 解析使用相同路径），
    // 避免星舰任务等"路径1/2 未命中"场景丢掉助推器数组。
    if (!launcherStagesArray) {
      const lsRaw = (launch.rocket && launch.rocket.launcher_stage)
        || (launch.rocket && launch.rocket.Launcher_stage)
        || (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.launcher_stage)
        || (launch.rocket && launch.rocket.configuration && launch.rocket.configuration.launcher_stage)
      if (lsRaw) {
        launcherStagesArray = Array.isArray(lsRaw) ? lsRaw : [lsRaw]
      }
    }

    if (launcherStagesArray && launcherStagesArray.length > 0) {
      boosterStages = launcherStagesArray.map((item, idx) => {
        if (!item || typeof item !== 'object') return null
        const innerLauncher = item.launcher || {}
        // 序列号
        let sn = innerLauncher.serial_number || item.serial_number || null
        if (!sn && item.landing && item.landing.description) {
          const m = item.landing.description.match(/B\d{3,5}/i)
          if (m) sn = m[0].toUpperCase()
        }
        // 星舰任务 Super Heavy 兜底用 launcher.name（如 "Booster 19"）
        if (!sn && innerLauncher.name) sn = innerLauncher.name
        // 飞行次数
        const fl = (item.launcher_flight_number !== undefined && item.launcher_flight_number !== null)
          ? item.launcher_flight_number
          : ((item.flights !== undefined && item.flights !== null) ? item.flights
            : ((innerLauncher.flights !== undefined && innerLauncher.flights !== null) ? innerLauncher.flights : null))
        // 着陆信息
        const ld = item.landing || (innerLauncher && innerLauncher.landing) || null
        const lloc = (ld && ld.landing_location) || null
        const labbrev = (lloc && lloc.abbrev) || null
        const lname = (lloc && lloc.name) || null
        // landingType 来源优先级：
        //   1) ld.type.abbrev —— LL2 标准字段（"EXP"/"RTLS"/"ASDS"/"SD" 等，最准）
        //   2) ld.type.name  —— 如 "Expended" / "Return to Launch Site"
        //   3) inferLandingTypeFromLocation(落点名) —— 兜底反推
        const ltypeRawObj = (ld && ld.type && typeof ld.type === 'object') ? ld.type : null
        const ltypeRaw = normalizeLandingType(
          (ltypeRawObj && (ltypeRawObj.abbrev || ltypeRawObj.name)) ||
          (ld && typeof ld.type === 'string' ? ld.type : null)
        )
        const ltype = ltypeRaw || inferLandingTypeFromLocation(labbrev, lname)
        const ldesc = (ld && ld.description) || null
        // 角色识别 —— 星舰任务的 launcher_stage[0].type 是 "Core"，会被 stageRoleMap
        // 错误识别为"中央芯"（中央芯是 Falcon Heavy 那种三芯火箭专属）。
        // 因此先按"火箭型号 + 数组长度"判断，再回落到通用 stageRoleMap。
        const roleRaw = String(item.type || item.position || item.role || '').toLowerCase()
        let roleLabel = ''
        const isStarshipRocket = /starship|超重|super\s*heavy/i.test(rocketName || '')
        const isFalconHeavyRocket = /falcon\s*heavy|猎鹰重型/i.test(rocketName || '')
        if (isStarshipRocket) {
          // 星舰只有两级：一级 = Super Heavy；飞船在 spacecraft_stage 里独立处理
          roleLabel = '超重助推器'
        } else if (isFalconHeavyRocket && launcherStagesArray.length >= 2) {
          // Falcon Heavy 有 1 中央芯 + 2 侧助推
          roleLabel = idx === 0 ? '中央芯' : `侧助推器 ${idx}`
        } else if (launcherStagesArray.length === 1) {
          // 单芯火箭（Falcon 9 / Electron / 长征 2/3/7 等）：无论 LL2 给什么 type，
          // 都只有一枚芯级 → 统一称"一级助推器"，避免把 LL2 的 "core" 解读为"中央芯"
          // （中央芯专指 Falcon Heavy 这种三芯火箭里"中间那一枚"的角色名）
          roleLabel = '一级助推器'
        } else if (stageRoleMap[roleRaw]) {
          // 其它多芯火箭（SLS / 长征五号 等）按 LL2 提供的 type 字段识别
          roleLabel = stageRoleMap[roleRaw]
          if (roleLabel === '侧助推器' && launcherStagesArray.length > 1) {
            roleLabel = `侧助推器 ${idx}`
          }
        } else if (launcherStagesArray.length > 1) {
          roleLabel = idx === 0 ? '主芯' : `助推器 ${idx}`
        } else {
          roleLabel = '一级助推器'
        }
        const reusedFlag = item.reused || innerLauncher.reused || false
        const lstatus = inferLandingStatus(ld, ltype)
        const display = buildLandingDisplay(ltype, labbrev || lname, reusedFlag, lstatus)
        // 星舰任务的 Super Heavy 助推器（如 Booster 19）不是 Falcon B10xx 那种回收族谱对象，
        // 而是一枚独立组合体硬件——它的详情展示在 progress 页"星舰组合体进展"卡片里，
        // 不走 booster-detail。给它打上 stageKind，由 mission-detail.openShipDetail 分发
        const isSuperHeavy = isStarshipRocket
        return {
          // stageKind 用于序列号 chip 跳转分发：
          //   'ship'                → 跳 progress 页并自动打开 Ship 卡片弹窗
          //   'super_heavy_booster' → 跳 progress 页并自动打开 Booster 卡片弹窗
          //   undefined             → 跳 booster-detail（Falcon 助推器 B10xx 族谱）
          stageKind: isSuperHeavy ? 'super_heavy_booster' : undefined,
          role: roleLabel,
          serialNumber: sn || null,
          flights: fl,
          successfulLandings: (innerLauncher.successful_landings != null)
            ? innerLauncher.successful_landings
            : (item.successful_landings != null ? item.successful_landings : null),
          attemptedLandings: (innerLauncher.attempted_landings != null)
            ? innerLauncher.attempted_landings
            : (item.attempted_landings != null ? item.attempted_landings : null),
          flightProven: item.flight_proven || innerLauncher.flight_proven || false,
          landingLocation: display.landingLocation,
          landingLocationAbbrev: labbrev || (lname && /^[A-Z0-9-]{2,10}$/.test(lname) ? lname : null),
          landingType: display.landingType,
          landingTypeLabel: display.landingTypeLabel,
          landingIcon: display.landingIcon,
          landingStatus: display.landingStatus,
          landingDisplayText: display.landingDisplayText,
          landingDescription: ldesc || null,
          reused: reusedFlag
        }
      }).filter(Boolean)

      // 第一个元素与已解析的主 boosterInfo 同步（保证兜底字段不丢）
      if (boosterInfo && boosterStages.length > 0) {
        boosterStages[0] = { ...boosterStages[0], ...boosterInfo, role: boosterStages[0].role }
      }
    }

    // 星舰任务：把 spacecraft_stage（Ship 39 / Starship）也加入 boosterStages
    const isStarshipMission = /starship|super\s*heavy|星舰|超重/i.test(String(rocketName || ''))
    if (isStarshipMission) {
      const ssRaw = (launch.rocket && launch.rocket.spacecraft_stage)
        || (launch.rocket && launch.rocket.configuration && launch.rocket.configuration.spacecraft_stage)
      const ssArr = ssRaw == null ? [] : (Array.isArray(ssRaw) ? ssRaw : [ssRaw])
      const shipStages = ssArr.map(it => {
        if (!it || typeof it !== 'object') return null
        const sc = (it && it.spacecraft) || it
        const scCfg = (sc && typeof sc.configuration === 'object') ? sc.configuration : null
        let sn = sc.serial_number || null
        if (!sn && typeof sc.name === 'string' && /^(ship|s)\s*\d+/i.test(sc.name)) sn = sc.name
        if (!sn && sc.name) sn = sc.name
        if (!sn && scCfg && scCfg.name) sn = scCfg.name
        const fl = (sc.flights_count != null) ? sc.flights_count
          : (sc.flights != null ? sc.flights : null)
        const ld = it.landing || sc.landing || null
        const lloc = (ld && ld.landing_location) || null
        const labbrev = (lloc && lloc.abbrev) || null
        const lname = (lloc && lloc.name) || null
        // 同 launcher_stage：优先读 ld.type.abbrev/name，其次按落点名反推
        const ltypeRawObjShip = (ld && ld.type && typeof ld.type === 'object') ? ld.type : null
        const ltypeRawShip = normalizeLandingType(
          (ltypeRawObjShip && (ltypeRawObjShip.abbrev || ltypeRawObjShip.name)) ||
          (ld && typeof ld.type === 'string' ? ld.type : null)
        )
        let ltypeShip = ltypeRawShip || inferLandingTypeFromLocation(labbrev, lname)
        // 飞船家族识别（按 LL2 spacecraft_config 字段，非启发式猜测）：
        //   Dragon 系列（Cargo Dragon 2 / Crew Dragon）→ 用龙飞船专属图标
        //   Starship/Ship 系列 → 保持 SPLASHDOWN（海面溅落）
        //   其它（Orion / Starliner / Soyuz / Shenzhou 等）→ 按 LL2 landing 字段走
        // 这样 LL2 没给 landing.type 的 Dragon 任务（LL2 通常只给 landing_location="Atlantic"）
        // 也能显示龙飞船图标，而不是 SPLASHDOWN 波浪图标
        const shipFamilyName = String(
          (scCfg && (scCfg.full_name || scCfg.name)) || sc.name || ''
        ).toLowerCase()
        const isDragonFamily = /dragon/.test(shipFamilyName)
        if (isDragonFamily) {
          ltypeShip = 'DRAGON'
        }
        // 飞船角色标签：LL2 有 full_name/name 就优先用
        let shipRoleLabel = '星舰飞船'
        if (isDragonFamily) {
          shipRoleLabel = (scCfg && scCfg.full_name) || (scCfg && scCfg.name) || '龙飞船'
        } else if (!/starship|super\s*heavy/.test(rocketName || '')) {
          // 非星舰 / 非龙飞船的飞船（Orion / Starliner / Dream Chaser 等）直接用配置名
          shipRoleLabel = (scCfg && scCfg.full_name) || (scCfg && scCfg.name) || sc.name || '飞船'
        }
        const reusedShip = sc.reused || false
        const lstatusShip = inferLandingStatus(ld, ltypeShip)
        const displayShip = buildLandingDisplay(ltypeShip, labbrev || lname, reusedShip, lstatusShip)
        return {
          stageKind: 'ship', // 区分这是飞船卡片，wxml 里据此决定点击跳转到 progress 页的 Ship 弹窗
          role: shipRoleLabel,
          serialNumber: sn || null,
          flights: fl,
          successfulLandings: null,
          attemptedLandings: null,
          flightProven: false,
          landingLocation: displayShip.landingLocation,
          landingLocationAbbrev: labbrev || null,
          landingType: displayShip.landingType,
          landingTypeLabel: displayShip.landingTypeLabel,
          landingIcon: displayShip.landingIcon,
          landingStatus: displayShip.landingStatus,
          landingDisplayText: displayShip.landingDisplayText,
          landingDescription: (ld && ld.description) || null,
          reused: reusedShip
        }
      }).filter(Boolean)
      if (shipStages.length > 0) {
        boosterStages = (boosterStages || []).concat(shipStages)
      }
    }

    

    
    // 发射服务商（launch_service_provider）
    const lsp = launch.launch_service_provider
    const launchServiceProvider = {
      id: (lsp && lsp.id != null) ? lsp.id : launchAgencyId,
      name: (lsp && lsp.name) || launchAgency || '',
      abbrev: (lsp && lsp.abbrev) || launchAgencyAbbrev || '',
      country: (lsp && lsp.country && lsp.country.name) || (lsp && lsp.country_code ? (COUNTRY_DISPLAY[(lsp.country_code || '').toUpperCase()] || lsp.country_code) : ''),
      website: (lsp && lsp.info_url) || (lsp && lsp.wiki_url) || null
    }
    
    // 任务完整信息（mission）；轨道优先 mission.orbit，并回落到各 payload 上的 orbit（与 LL2 实际返回一致）
    const orbitResolved = resolveLaunchOrbitStrings(launch)
    const orbitStr = orbitResolved.display || orbitResolved.shortLabel
    const missionFull = {
      name: (mission && mission.name) || '',
      description: (mission && mission.description) || '',
      type: (mission && mission.type && (typeof mission.type === 'string' ? mission.type : (mission.type && mission.type.name))) || '',
      orbit: orbitStr
    }
    
    // 火箭配置完整信息（rocket.configuration）
    const rocketFull = {
      configuration: getRocketDisplayNameFromConfig(rocketConfig),
      description: (rocketConfig && rocketConfig.description) || '',
      manufacturer: (rocketConfig && rocketConfig.manufacturer && rocketConfig.manufacturer.name) || ''
    }

    const { rocketSpecsVisible, rocketSpecs } = buildRocketSpecsForDetail(rocketConfig)
    
    // 发射场地完整信息（pad + location）
    const pad = launch.pad
    const loc = (pad && pad.location)
    const padName = (pad && pad.name) || ''
    const locName = (loc && loc.name) || ''
    const padCountry = (loc && loc.country_code) ? (COUNTRY_DISPLAY[(loc.country_code || '').toUpperCase()] || loc.country_code) : (loc && loc.country && loc.country.name) || ''
    const padCoords = (pad && pad.latitude != null && pad.longitude != null) ? { lat: pad.latitude, lng: pad.longitude } : (loc && loc.latitude != null && loc.longitude != null ? { lat: loc.latitude, lng: loc.longitude } : null)
    const totalLaunchCount = (pad && pad.total_launch_count != null ? pad.total_launch_count : (loc && loc.total_launch_count != null ? loc.total_launch_count : null))
    const nameLower = (padName + ' ' + locName).toLowerCase()
    const padType = /ship|marine|sea|海上|mobile|maritime|drone|asds|floating|海上/.test(nameLower) ? '海上' : '陆上'
    const padDetail = {
      padName,
      locationName: locName,
      country: padCountry,
      state: null,
      city: null,
      latitude: padCoords && padCoords.lat,
      longitude: padCoords && padCoords.lng,
      padType,
      totalLaunchCount
    }
    
    // 飞行 & 着陆全量统计（从 launcher/landing 能取则取，多数 API 无细粒度时序）
    const flightStats = {
      boosterIgnition: null,
      firstStageSep: null,
      secondStageOrbit: null,
      fairingSep: null,
      payloadOrbit: null
    }
    const landingStats = {
      sepAltitude: null,
      sepVelocity: null,
      reentryTime: null,
      landingBurnTime: null,
      landingTime: null,
      deviationDistance: null
    }
    const fl = (launcher && launcher.launcher_flight_number != null ? launcher.launcher_flight_number : (launcher && launcher.flights != null ? launcher.flights : undefined))
    const general = {
      totalFlightDuration: null,
      orbitAccuracy: orbitResolved.shortLabel || null,
      payloadWeight: null,
      flights: fl != null ? fl : null
    }
    const launcherLanding = { flightStats, landingStats, general }
    const missionDescLong = ((missionFull.description || '').length > 100)
    const rocketDescLong = ((rocketFull.description || '').length > 100)
    
    const status = launch.status || {}
    const statusCategory = getStatusCategory(status)
    const statusBadgeText = getStatusBadgeText(status, statusCategory)
    
    // 根据 launch 的 payload_flights、mission.payloads 或 /payload_flights/ 取 payload id 与 amount，再请求 /payloads/{id}/
    // 优化：优先使用launch详情中已有的payload信息，避免不必要的API调用
    let payloadDetails = []
    let payloadAmount = 0
    const amt = (r) => (r != null && r.amount != null && !isNaN(Number(r.amount)) ? Number(r.amount) : 1)
    const collectId = (p) => {
      if (p == null) return null
      if (typeof p === 'number' || (typeof p === 'string' && /^\d+$/.test(p))) return p
      if (typeof p === 'object' && p.id != null) return p.id
      if (typeof p === 'string' && p.indexOf('/') >= 0) return p.split('/').filter(Boolean).pop()
      return null
    }
    const ids = []
    const addId = (id) => { if (id != null && id !== '' && !ids.includes(id)) ids.push(id) }
    
    // 优先从launch.payload_flights获取payload信息
    if (Array.isArray(launch.payload_flights) && launch.payload_flights.length > 0) {
      for (const r of launch.payload_flights) {
        addId(collectId(r.payload))
        payloadAmount += amt(r)
      }
    }
    // 如果payload_flights为空，尝试从mission.payloads获取
    if (ids.length === 0 && launch.mission && launch.mission.payloads && Array.isArray(launch.mission.payloads) && launch.mission.payloads.length > 0) {
      for (const p of launch.mission.payloads) { addId(collectId(p)) }
      payloadAmount += launch.mission.payloads.length
    }
    // 优化：只在确实没有payload信息时才调用回退查询
    // 如果launch详情中没有payload_flights和mission.payloads，说明API可能不支持，回退查询也可能失败
    // 为了减少不必要的API调用，只在开发环境且确实需要时才调用
    if (ids.length === 0 && USE_DEV_API) {
      try {
        // 使用较短的超时时间，避免长时间等待
        const pfRes = await request('/payload_flights/', { launch: launch.id, limit: 50, mode: 'list' }, 5000, true)
        const raw = (pfRes && pfRes.results) || []
        const lid = String(launch.id)
        for (const r of raw) {
          const l = r.launch
          const lidR = l != null ? (l.id != null ? l.id : (typeof l === 'string' ? l.split('/').filter(Boolean).pop() : null)) : null
          if (lidR != null && String(lidR) === lid) {
            addId(collectId(r.payload))
            payloadAmount += amt(r)
          }
        }
      } catch (e) { 
        // 静默失败，不影响主流程
      }
    }
    // 优化：只在有payload ID且确实需要详细信息时才请求
    // 如果launch详情中已经包含了足够的payload信息，就不需要额外请求
    if (ids.length > 0) {
      // 优化：限制最多请求5个payload详情，避免请求过多
      // 大多数情况下，payload详情不是必需的，可以显示基本信息即可
      const maxPayloadRequests = 5
      const payloadIdsToRequest = ids.slice(0, maxPayloadRequests)
      for (const id of payloadIdsToRequest) {
        try {
          // 使用较短的超时时间，避免长时间等待
          const d = await getPayloadDetail(id)
          payloadDetails.push({ ...d, _wxkey: `p-${id}-${payloadDetails.length}` })
        } catch (e) {
          // 静默失败，不影响其它payload
        }
      }
    }
    // 若 mission 未展开轨道，但载荷详情接口带了 orbit，则用其补全「任务轨道」展示
    if (!missionFull.orbit && payloadDetails.length > 0) {
      for (const pd of payloadDetails) {
        const od = pd.orbitDisplay != null ? String(pd.orbitDisplay).trim() : ''
        if (od) {
          missionFull.orbit = od
          break
        }
      }
    }
    // 若 payload_flights / mission.payloads / payload_flights API 都未得到数量，尝试从 mission.description 文本中解析
    if (payloadAmount <= 0 && mission && mission.description) {
      const fromDesc = tryExtractPayloadCountFromDescription(mission.description)
      if (fromDesc > 0) payloadAmount = fromDesc
    }

    // 一二级箭体：从 launcher_stage、spacecraft_stage 提取型号与序列号，回收信息预留
    let firstStage = null
    let secondStage = null
    const _starshipCheck = [(rocketConfig && rocketConfig.full_name), (rocketConfig && rocketConfig.name), launch.name, (mission && mission.name), (mission && mission.description)].filter(Boolean).join(' ')
    const isStarship = /starship/i.test(_starshipCheck)

    // 一级/助推器：launcher_stage（数组或单对象）
    const ls = (launch.rocket && launch.rocket.launcher_stage) || (launch.rocket && launch.rocket.Launcher_stage) || (launch.rocket && launch.rocket.rocket && launch.rocket.rocket.launcher_stage) || (launch.rocket && launch.rocket.configuration && launch.rocket.configuration.launcher_stage)
    const launcherArr = ls == null ? [] : (Array.isArray(ls) ? ls : [ls])
    for (const it of launcherArr) {
      if (!it || typeof it !== 'object') continue
      const l = it.launcher || it
      const cfg = (l && typeof l.configuration === 'object') ? l.configuration : null
      const sn = (l && l.serial_number != null ? l.serial_number : it.serial_number)
      const land = it.landing || (l && l.landing)
      const loc = land && land.landing_location
      let lt = (loc && loc.type && String(loc.type).toUpperCase() === 'ASDS') ? 'ASDS' : ((loc && loc.type && String(loc.type).toUpperCase() === 'RTLS') ? 'RTLS' : null)
      if (!lt && (loc && (loc.abbrev || loc.name))) {
        const t = String(loc.abbrev || loc.name || '').toUpperCase()
        if (/ASOG|OCISLY|JRTI|A SHORTFALL|OF COURSE I STILL|JUST READ THE INSTRUCTIONS/.test(t)) lt = 'ASDS'
        else if (/LZ-|LANDING ZONE|LZ1|LZ2|LZ4/.test(t)) lt = 'RTLS'
      }
      firstStage = {
        name: ((cfg && cfg.full_name) || (cfg && cfg.name)) || (isStarship ? 'Super Heavy' : null) || '一级助推器',
        serialNumber: sn || null,
        reusable: !!(land || (l && l.reused === true)) || isStarship,
        recoveryStatus: null,
        landingType: lt || null,
        landingLocation: (loc && (loc.abbrev || loc.name)) || null
      }
      break
    }

    // 二级/上面级：spacecraft_stage（数组或单对象 { spacecraft: { name, serial_number } }）
    const ss = (launch.rocket && launch.rocket.spacecraft_stage) || (launch.rocket && launch.rocket.configuration && launch.rocket.configuration.spacecraft_stage)
    const scArr = ss == null ? [] : (Array.isArray(ss) ? ss : [ss])
    for (const it of scArr) {
      const sc = (it && it.spacecraft) || it
      if (!sc || typeof sc !== 'object') continue
      const scCfg = (sc && typeof sc.configuration === 'object') ? sc.configuration : null
      const name = ((scCfg && scCfg.full_name) || (scCfg && scCfg.name)) || sc.name || (isStarship ? 'Starship' : null) || '二级/上面级'
      const sn = sc.serial_number || (typeof sc.name === 'string' && /^(ship|s)\s*\d+/i.test(sc.name) ? sc.name : null)

      // "可回收" 推断链（LL2 字段优先，兜底启发式）：
      //   1) spacecraft_config.reusable 显式 true/false  ← LL2 最准的字段（Dragon/Starship 都会给）
      //   2) spacecraft.reusable 本体字段               ← 少数响应有
      //   3) 飞船家族名关键词：Dragon / Starship / Orion / Crew Dragon / Cargo Dragon 等
      //   4) 星舰任务整体兜底                           ← 保留原逻辑
      //   5) 否则一律视为一次性
      //
      // 之前的 `reusable: isStarship` 只认星舰，导致 Dragon CRS 任务的 Cargo Dragon 2 
      // 显示"可回收 否"，与实际严重不符（NASA 二代货运龙支持最多 5 次复用）
      let reusableFlag = null
      if (scCfg && typeof scCfg.reusable === 'boolean') {
        reusableFlag = scCfg.reusable
      } else if (typeof sc.reusable === 'boolean') {
        reusableFlag = sc.reusable
      }
      if (reusableFlag === null) {
        const reusableCheckText = [name, scCfg && scCfg.name, sc.name].filter(Boolean).join(' ').toLowerCase()
        if (/dragon|starship|super\s*heavy|orion|dream\s*chaser|starliner/i.test(reusableCheckText)) {
          reusableFlag = true
        } else if (isStarship) {
          reusableFlag = true
        } else {
          reusableFlag = false
        }
      }

      secondStage = {
        name,
        serialNumber: sn || null,
        reusable: reusableFlag,
        recoveryStatus: null,
        landingType: null,
        landingLocation: null
      }
      break
    }
    const bothReusable = isStarship && (firstStage != null || secondStage != null)
    const stageInfo = { firstStage, secondStage, bothReusable }

    // 直播 / 视频源（LL2 详情端点会返回，列表里通常没有；
    // 字段名两种命名都兼容：vidURLs(camel) / vid_urls(snake)）
    const rawVidUrls = launch.vidURLs || launch.vid_urls || []
    const vidUrls = Array.isArray(rawVidUrls)
      ? rawVidUrls
          .filter(item => item && typeof item.url === 'string' && /^https?:\/\//i.test(item.url))
          .map(item => ({
            url: item.url,
            title: item.title || '',
            description: item.description || '',
            publisher: item.publisher || '',
            language: (item.language && item.language.name) || '',
            type: (item.type && item.type.name) || '',
            priority: item.priority != null ? item.priority : 0
          }))
          .sort((a, b) => (a.priority || 0) - (b.priority || 0))
      : []

    const rawInfoUrls = launch.infoURLs || launch.info_urls || []
    const infoUrls = Array.isArray(rawInfoUrls)
      ? rawInfoUrls
          .filter(item => item && typeof item.url === 'string' && /^https?:\/\//i.test(item.url))
          .map(item => ({
            url: item.url,
            title: item.title || '',
            publisher: item.publisher || ''
          }))
      : []

    const webcastLive = !!(launch.webcast_live === true || launch.webcastLive === true)

    return {
      id: launch.id,
      name: launch.name || '',
      missionName: (launch.mission && launch.mission.name) || launch.name || '未知任务',
      launchTime: launch.net || launch.window_start || launch.window_end,
      windowStart: launch.window_start,
      windowEnd: launch.window_end,
      description: description,
      missionDetails: missionDetails,
      rocketInfo: rocketInfo,
      launchAgency: launchAgency,
      launchAgencyId: launchAgencyId,
      launchAgencyAbbrev: launchAgencyAbbrev,
      launchSite: launchSite,
      padLocation: formatPadLocation(launch.pad),
      rocketName: getRocketDisplayNameFromConfig(rocketConfig),
      status: status.name || '未知状态',
      statusCategory,
      statusBadgeText,
      probability: launch.probability,
      boosterInfo: boosterInfo,
      boosterStages: boosterStages,
      isRecoverableThisMission: isRecoverable(boosterInfo),
      launchServiceProvider,
      missionFull,
      rocketFull,
      padDetail,
      launcherLanding,
      missionDescLong,
      rocketDescLong,
      payloadDetails,
      payloadAmount: payloadAmount > 0 ? payloadAmount : null,
      stageInfo,
      vidUrls,
      infoUrls,
      webcastLive,
      rocketImage: getRocketImage(getRocketDisplayNameFromConfig(rocketConfig)),
      rocketConfiguration: pickRocketConfigurationSnapshot(launch),
      rocketSpecsVisible,
      rocketSpecs
    }
}

/**
 * 获取已完成的任务列表（使用 /launches/previous/ 端点）
 * 使用 /launches/previous/ 端点获取已完成的任务
 * @param {Number} limit 返回数量，默认10
 * @param {Number} offset 偏移量，默认0
 * @returns {Promise} 返回已完成任务列表
 */
function getCompletedMissions(limit = 10, offset = 0) {
  // 使用 /launches/previous/ 端点获取已完成的任务
  return request('/launches/previous/', {
    limit: limit,
    offset: offset,
    ordering: '-net', // 按时间倒序，最新的在前
    mode: 'detailed',
    format: 'json' // 明确指定JSON格式
  }).then(data => {
    if (!data) return emptyListResult()
    if (!data.results || !Array.isArray(data.results)) return emptyListResult()
    
    const completedLaunches = data.results
    
    const list = completedLaunches.map((launch, index) => mapLaunchToListItem(launch, index, offset, 'completed'))
    // 仅依赖 data.next 在“从缓存切片返回”时不可靠（next 可能为 null 或被构造为占位）
    // 这里按“实际可用总量 vs 本次返回量”计算，确保能滚动加载到缓存末尾
    const actualReturnedCount = list.length
    const totalAvailable = Array.isArray(data.results) ? data.results.length : (data.count || 0)
    const hasMore = (offset + actualReturnedCount) < totalAvailable || !!(data && data.next)
    return { list, hasMore: hasMore, nextOffset: offset + actualReturnedCount }
  }).catch(error => {
    throw error
  })
}


