/**
 * 从云数据库获取封路通知
 * 仅查询 road_closure_notice 集合（含 starbase_gov / spacedevs / manual 三种来源）
 */
async function getRoadClosureNoticeFromDB() {
  try {
    if (!wx.cloud || !wx.cloud.database) {
      return null
    }

    const db = wx.cloud.database()
    const now = Date.now()

    const newResult = await Promise.race([
      db.collection('road_closure_notice').where({ isActive: true }).limit(20).get(),
      new Promise((resolve) => setTimeout(() => resolve({ data: [] }), 5000))
    ]).catch(() => ({ data: [] }))

    const candidates = []

    const STALE_TTL = 24 * 60 * 60 * 1000

    const newList = (newResult && newResult.data) || []
    for (const item of newList) {
      if (!item.isActive) continue
      if (item.endAt && item.endAt > 0 && item.endAt < now) continue
      if ((!item.endAt || item.endAt === 0) && item.syncedAt && (now - item.syncedAt > STALE_TTL)) continue
      const priority = (item.source === 'manual' ? 999 : 0) + (item.priority || 0)
      candidates.push({
        isActive: true,
        message: item.message || item.statusText || '道路封路通知',
        startTime: item.startAt || 0,
        endTime: item.endAt || 0,
        timeRange: item.timeRange || '',
        source: item.source || 'unknown',
        beachStatus: item.beachStatus || '',
        beachClosureSchedule: item.beachClosureSchedule || [],
        roadDelays: item.roadDelays || [],
        roadUpdates: item.roadUpdates || [],
        _priority: priority
      })
    }

    if (candidates.length === 0) {
      return null
    }

    candidates.sort((a, b) => b._priority - a._priority)
    const best = candidates[0]
    delete best._priority
    return best
  } catch (error) {
    return null
  }
}

const ROAD_CLOSURE_CACHE_KEY = '_road_closure_local_cache'
const ROAD_CLOSURE_CACHE_TTL = 5 * 60 * 1000
let _roadClosurePending = null
// 内存缓存：避免首屏频繁同步读 storage（wx 启动性能告警）
let _roadClosureMemCache = null // { data, timestamp }

function _readRoadClosureFromStorageAsync() {
  return new Promise((resolve) => {
    wx.getStorage({
      key: ROAD_CLOSURE_CACHE_KEY,
      success: (res) => resolve(res && res.data ? res.data : null),
      fail: () => resolve(null)
    })
  })
}

/**
 * 获取封路通知
 * 优先从内存/本地缓存读取（5分钟 TTL），减少云数据库读取
 * 其次从云数据库 road_closure_notice 获取
 * 最后从 events/upcoming API 缓存中筛选
 * 内置 Promise 去重，多页面同时调用只查一次
 */
async function getRoadClosureNotice() {
  // Phase 0: 内存缓存（零阻塞）
  if (_roadClosureMemCache && _roadClosureMemCache.timestamp &&
      (Date.now() - _roadClosureMemCache.timestamp < ROAD_CLOSURE_CACHE_TTL)) {
    return _roadClosureMemCache.data
  }

  // Phase 1: 异步读本地存储，不阻塞主线程
  try {
    const cached = await _readRoadClosureFromStorageAsync()
    if (cached && cached.timestamp && (Date.now() - cached.timestamp < ROAD_CLOSURE_CACHE_TTL)) {
      _roadClosureMemCache = cached
      return cached.data
    }
  } catch (e) {}

  if (_roadClosurePending) return _roadClosurePending
  _roadClosurePending = _fetchRoadClosureNotice()
  try {
    return await _roadClosurePending
  } finally {
    _roadClosurePending = null
  }
}

async function _fetchRoadClosureNotice() {
  try {
    const dbResult = await Promise.race([
      getRoadClosureNoticeFromDB(),
      new Promise((resolve) => setTimeout(() => resolve(null), 5000))
    ])

    if (dbResult && dbResult.isActive === true) {
      _saveRoadClosureCache(dbResult)
      return dbResult
    }
  } catch (error) {
    // 静默失败
  }

  // DB 无数据时，从缓存的 events 中筛选
  try {
    const data = await request('/events/upcoming/', {
      limit: 100,
      offset: 0
    }, 5000, true)

    if (data && data.results && data.results.length > 0) {
      const now = Date.now()

      const roadClosureEvent = data.results.find(event => {
        const eventType = (event.type && event.type.name && event.type.name.toLowerCase()) || ''
        const eventName = (event.name && event.name.toLowerCase()) || ''
        const eventDescription = (event.description && event.description.toLowerCase()) || ''

        const isRoadClosure = eventType.includes('road') ||
               eventType.includes('closure') ||
               eventName.includes('road') ||
               eventName.includes('closure') ||
               eventDescription.includes('road closure') ||
               eventDescription.includes('封路')

        if (!isRoadClosure) return false

        const endTime = event.window_end ? new Date(event.window_end).getTime()
          : event.date ? new Date(event.date).getTime() : 0
        return endTime > now
      })

      if (roadClosureEvent) {
        const startTime = roadClosureEvent.date
          ? new Date(roadClosureEvent.date).getTime()
          : roadClosureEvent.window_start
            ? new Date(roadClosureEvent.window_start).getTime()
            : null
        const endTime = roadClosureEvent.window_end
          ? new Date(roadClosureEvent.window_end).getTime()
          : roadClosureEvent.date
            ? new Date(roadClosureEvent.date).getTime()
            : null

        const result = {
          isActive: true,
          message: roadClosureEvent.name || '星舰基地发射前道路封路通知',
          startTime,
          endTime
        }
        _saveRoadClosureCache(result)
        return result
      }
    }
  } catch (error) {
    // 静默失败
  }

  const emptyResult = { isActive: false, message: '', startTime: null, endTime: null }
  _saveRoadClosureCache(emptyResult)
  return emptyResult
}

function _saveRoadClosureCache(data) {
  const payload = { data, timestamp: Date.now() }
  _roadClosureMemCache = payload
  try {
    // 异步写入 storage，避免阻塞主线程
    wx.setStorage({ key: ROAD_CLOSURE_CACHE_KEY, data: payload, fail: () => {} })
  } catch (e) {}
}

/**
 * 获取事件列表
 * 使用 updates API 获取航天相关更新/事件
 * @param {Number} page 页码（从1开始）
 * @param {Number} limit 每页数量
 * @returns {Promise} 返回事件列表
 */
/**
 * Spaceflight News（云缓存 / 直连）按固定 offset 截取一页，sliceLimit 为条数
 */
function manualNewsDocToFormattedItem(doc) {
  if (!doc || !doc._id) return null
  let publishedAt = doc.publishedAt || doc.date || ''
  if (!publishedAt && doc.updatedAt) {
    publishedAt = new Date(doc.updatedAt).toISOString()
  }
  if (!publishedAt) {
    publishedAt = new Date().toISOString()
  }
  const authorName = (doc.author && String(doc.author).trim())
    ? String(doc.author).trim()
    : '火星探索日志'
  return {
    id: `manual_${doc._id}`,
    title: doc.title || '无标题',
    summary: doc.summary || '',
    author: authorName,
    newsSite: doc.newsSite || '官方',
    publishedAt,
    image: doc.image || '',
    url: doc.url || '',
    type: 'article',
    content: doc.content || '',
    isManual: true
  }
}

async function fetchSpaceflightArticlesSlice(apiOffset, sliceLimit) {
  const offset = apiOffset
  const limit = sliceLimit

  if (!wx.cloud || !wx.cloud.database) {
    throw new Error('云开发未初始化')
  }
  if (!limit || limit < 1) {
    return { list: [], total: 0, page: 1, limit: 0, hasMore: false }
  }

  const db = wx.cloud.database()

  const exactCacheKey = getCacheKey('/articles/', { format: 'json', limit, offset, ordering: '-published_at' })

  let exactData = null
  try {
    const docResult = await Promise.race([
      db.collection('space_devs_cache').doc(exactCacheKey).get(),
      new Promise((_, reject) =>
        setTimeout(() => reject(new Error('数据库查询超时')), 5000)
      )
    ])

    if (docResult.data && docResult.data.data) {
      const docData = docResult.data.data
      const now = Date.now()

      if (!docData.expireAt || now <= docData.expireAt) {
        let apiData = docData.data

        apiData = unwrapCacheData(apiData)

        if (apiData && apiData.results && Array.isArray(apiData.results)) {
          exactData = apiData
        }
      }
    }
  } catch (error) {}

  const pageNum = Math.floor(offset / limit) + 1
  if (exactData) {
    return formatArticlesData(exactData, pageNum, limit)
  }

  const similarParams = { format: 'json', limit: 100, offset: 0, ordering: '-published_at' }
  const similarKey = getCacheKey('/articles/', similarParams)

  try {
    const similarResult = await Promise.race([
      db.collection('space_devs_cache').doc(similarKey).get(),
      new Promise((_, reject) =>
        setTimeout(() => reject(new Error('数据库查询超时')), 5000)
      )
    ])

    if (similarResult.data && similarResult.data.data) {
      const similarDocData = similarResult.data.data
      const now = Date.now()

      if (!similarDocData.expireAt || now <= similarDocData.expireAt) {
        let similarApiData = null

        if (similarDocData.data) {
          similarApiData = similarDocData.data
        } else if (similarDocData.results && Array.isArray(similarDocData.results)) {
          similarApiData = similarDocData
        } else {
          for (const key in similarDocData) {
            if (key !== 'timestamp' && key !== 'expireAt' && key !== 'updatedAt') {
              const value = similarDocData[key]
              if (value && typeof value === 'object' && value.results && Array.isArray(value.results)) {
                similarApiData = value
                break
              }
            }
          }
        }

        if (similarApiData && typeof similarApiData === 'object' && !Array.isArray(similarApiData)) {
          if (!similarApiData.results && similarApiData.data && typeof similarApiData.data === 'object') {
            if (similarApiData.data.results && Array.isArray(similarApiData.data.results)) {
              similarApiData = similarApiData.data
            }
          }
        }

        if (similarApiData && similarApiData.results && Array.isArray(similarApiData.results)) {
          const startIndex = offset
          const endIndex = offset + limit
          const totalAvailable = similarApiData.results.length
          const limitedResults = similarApiData.results.slice(startIndex, endIndex)

          const hasMore = endIndex < totalAvailable || similarApiData.next !== null

          const limitedData = {
            ...similarApiData,
            results: limitedResults,
            count: similarApiData.count || totalAvailable,
            next: hasMore ? (similarApiData.next || 'has_more') : null
          }

          return formatArticlesData(limitedData, pageNum, limit)
        }
      }
    }
  } catch (error) {
    try {
      const fallbackParams = { format: 'json', limit: 20, offset: 0, ordering: '-published_at' }
      const fallbackKey = getCacheKey('/articles/', fallbackParams)

      const fallbackResult = await Promise.race([
        db.collection('space_devs_cache').doc(fallbackKey).get(),
        new Promise((_, reject) =>
          setTimeout(() => reject(new Error('数据库查询超时')), 5000)
        )
      ])

      if (fallbackResult.data && fallbackResult.data.data) {
        const fallbackDocData = fallbackResult.data.data
        const now = Date.now()

        if (!fallbackDocData.expireAt || now <= fallbackDocData.expireAt) {
          let fallbackApiData = fallbackDocData.data || fallbackDocData

          if (fallbackApiData && typeof fallbackApiData === 'object' && !Array.isArray(fallbackApiData)) {
            if (fallbackApiData.data && fallbackApiData.data.results && Array.isArray(fallbackApiData.data.results)) {
              fallbackApiData = fallbackApiData.data
            }
          }

          if (fallbackApiData && fallbackApiData.results && Array.isArray(fallbackApiData.results)) {
            const startIndex = offset
            const endIndex = offset + limit
            const limitedResults = fallbackApiData.results.slice(startIndex, endIndex)

            const limitedData = {
              ...fallbackApiData,
              results: limitedResults,
              count: fallbackApiData.count || fallbackApiData.results.length,
              next: endIndex < fallbackApiData.results.length ? (fallbackApiData.next || 'has_more') : null
            }

            return formatArticlesData(limitedData, pageNum, limit)
          }
        }
      }
    } catch (fallbackError) {}
  }

  try {
    const directApiData = await new Promise((resolve, reject) => {
      wx.request({
        url: 'https://api.spaceflightnewsapi.net/v4/articles/',
        method: 'GET',
        data: {
          format: 'json',
          limit,
          offset,
          ordering: '-published_at'
        },
        timeout: 8000,
        success: (res) => {
          if (res.statusCode >= 200 && res.statusCode < 300 && res.data) {
            resolve(res.data)
          } else {
            reject(new Error(`事件API请求失败: ${res.statusCode}`))
          }
        },
        fail: (err) => {
          reject(new Error(err.errMsg || '事件API请求失败'))
        }
      })
    })

    if (directApiData && directApiData.results && Array.isArray(directApiData.results)) {
      return formatArticlesData(directApiData, pageNum, limit)
    }
  } catch (directError) {}

  throw new Error('数据库中没有找到文章数据')
}

