const { getSystemInfo } = require('../../utils/system.js')
const { getRoadClosureNotice } = require('../../utils/api.js')
const { ROAD_CLOSURE_SCENE } = require('../../utils/map-scenes.js')
const { ROUTES } = require('../../utils/routes.js')
const pageBase = require('../../utils/page-base.js')

function formatUpdateTime(ts) {
  if (!ts) return ''
  const d = new Date(ts)
  const pad = n => String(n).padStart(2, '0')
  return d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate()) + ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes())
}

const SOURCE_LABELS = {
  starbase_gov: 'Starbase.gov',
  spacedevs: 'SpaceDevs',
  manual: '管理员'
}

Page({
  behaviors: [pageBase],
  _fallbackTab: '/pages/progress/progress',

  data: {
    loading: true,
    errorMessage: '',
    item: null,
    shareTitle: '星舰基地封路通知 | 火星探索日志',
    statusBarHeight: 44,
    navPlaceholderHeight: 0,
    tabBarReservedHeight: 0,
    menuButtonWidth: 88,
    mapLatitude: ROAD_CLOSURE_SCENE.center.latitude,
    mapLongitude: ROAD_CLOSURE_SCENE.center.longitude,
    mapScale: 13,
    mapMarkers: ROAD_CLOSURE_SCENE.markers,
    mapPolylines: ROAD_CLOSURE_SCENE.polylines,
    mapPolygons: ROAD_CLOSURE_SCENE.polygons
  },

  onLoad() {
    this.initUiShell()

    wx.showShareMenu({
      withShareTicket: true,
      menus: ['shareAppMessage', 'shareTimeline']
    })

    this.loadData()
  },

  async loadData() {
    this.setData({ loading: true, errorMessage: '' })
    try {
      const data = await getRoadClosureNotice()
      if (!data || !data.isActive) {
        this.setData({ loading: false, item: null })
        return
      }

      const sourceLabel = SOURCE_LABELS[data.source] || data.source || ''
      const updatedAtText = formatUpdateTime(data.updatedAt || data.syncedAt)
      const beachOpen = data.beachOpen
      const roadOpen = data.roadOpen
      let statusTitle = '交通管制信息'
      if (beachOpen === false && roadOpen === false) statusTitle = '海滩及道路封闭中'
      else if (beachOpen === false) statusTitle = '海滩封闭中'
      else if (roadOpen === false) statusTitle = '道路封闭中'

      const item = {
        ...data,
        sourceLabel,
        updatedAtText,
        statusTitle
      }

      const lines = ['星舰基地封路通知']
      if (data.message) lines.push(data.message)
      if (data.timeRange) lines.push(data.timeRange)

      this.setData({
        loading: false,
        item,
        shareTitle: lines.join(' | ') + ' | 火星探索日志'
      })
    } catch (error) {
      this.setData({
        loading: false,
        errorMessage: (error && (error.errMsg || error.message)) || '封路通知加载失败'
      })
    }
  },

  retryLoad() {
    this.loadData()
  },

  // goBack inherited from pageBase with _fallbackTab

  openFullMap() {
    const item = this.data.item
    const query = [
      'message=' + encodeURIComponent((item && item.message) || ''),
      'timeRange=' + encodeURIComponent((item && item.timeRange) || '')
    ].join('&')
    wx.navigateTo({ url: ROUTES.ROAD_CLOSURE_MAP + '?' + query })
  },

  onShareAppMessage() {
    return {
      title: this.data.shareTitle,
      path: '/pages/progress/road-closure-detail',
      imageUrl: ''
    }
  },

  onShareTimeline() {
    return {
      title: this.data.shareTitle,
      imageUrl: ''
    }
  }
})
